-- ============================================================================
-- TradeArena — full database bootstrap
-- Generated by combining 0001..0004 in order. Safe to re-run.
-- Paste this whole file into Supabase Dashboard → SQL Editor → New Query → Run.
-- After it succeeds, optionally run:  select public.seed_starter_schools();
-- ============================================================================

-- ===== 0001_init.sql ===========================================================
-- TradeArena — initial schema (Task #2 foundation)
-- Run this once in Supabase Dashboard → SQL Editor.
--
-- Tables created here are designed to support the full product roadmap:
--   - profiles, strategies, paper_trades, holdings (Task #3 — trader scorecard)
--   - reels, reel_tags, reel_mirrors (Task #4 — strategy reels feed)
--   - chart_layouts, price_bars (Task #2b — pro charts)
--   - schools, modules, quizzes, challenges, perks (Task #5 — education)
--   - follows, leagues, league_members (social + competition)
--
-- RLS policies are written conservatively: owner-only writes, public reads
-- where it makes sense, and a `visibility_mask` on profiles so traders can
-- pick exactly which sections of their page are public.

-- ============================================================
-- Extensions
-- ============================================================
create extension if not exists pgcrypto;
create extension if not exists "uuid-ossp";

-- ============================================================
-- profiles  (1-to-1 with auth.users)
-- ============================================================
-- Note: profiles intentionally does NOT store email. The canonical email lives
-- in auth.users; duplicating it here would create a PII enumeration surface.
create table if not exists public.profiles (
  id              uuid primary key references auth.users(id) on delete cascade,
  username        text unique not null check (username ~ '^[a-z][a-z0-9_]{2,19}$'),
  display_name    text not null,
  university      text not null default 'Public',
  tier            text not null default 'Member',           -- Student | Member | Pro
  type            text not null default 'public',           -- student | public
  bio             text default '',
  avatar_color    text,
  is_admin        boolean not null default false,
  visibility_mask jsonb not null default '{
    "holdings":      false,
    "cash":          false,
    "equity_curve":  true,
    "metrics":       true,
    "strategies":    true,
    "journal":       true,
    "reels":         true,
    "university":    true
  }'::jsonb,
  badges          text[] not null default '{}'::text[],
  created_at      timestamptz not null default now(),
  updated_at      timestamptz not null default now()
);

create index if not exists profiles_username_lower_idx on public.profiles (lower(username));
create index if not exists profiles_university_idx     on public.profiles (university);

-- ============================================================
-- strategies
-- ============================================================
create table if not exists public.strategies (
  id          uuid primary key default gen_random_uuid(),
  owner_id    uuid not null references public.profiles(id) on delete cascade,
  name        text not null,
  description text default '',
  rules       jsonb not null default '{}'::jsonb,
  created_at  timestamptz not null default now()
);
create index if not exists strategies_owner_idx on public.strategies(owner_id);

-- ============================================================
-- paper_trades
-- ============================================================
create table if not exists public.paper_trades (
  id              uuid primary key default gen_random_uuid(),
  owner_id        uuid not null references public.profiles(id) on delete cascade,
  symbol          text not null,
  market          text,                                       -- asx | us | crypto
  side            text not null check (side in ('buy','sell')),
  qty             numeric(20,8) not null,
  entry_price     numeric(20,8) not null,
  exit_price      numeric(20,8),
  stop_loss       numeric(20,8),
  target          numeric(20,8),
  status          text not null default 'open' check (status in ('open','closed','cancelled')),
  opened_at       timestamptz not null default now(),
  closed_at       timestamptz,
  source_reel_id  uuid,                                       -- FK added later (chicken/egg with reels)
  notes           text default ''
);
create index if not exists paper_trades_owner_idx  on public.paper_trades(owner_id);
create index if not exists paper_trades_status_idx on public.paper_trades(owner_id, status);

-- ============================================================
-- reels  (the social trade-idea feed)
-- ============================================================
create table if not exists public.reels (
  id                  uuid primary key default gen_random_uuid(),
  author_id           uuid not null references public.profiles(id) on delete cascade,
  symbol              text not null,
  market              text,
  chart_snapshot_url  text,                                   -- storage URL or data URL
  thesis              text not null check (length(thesis) <= 280),
  entry               numeric(20,8),
  stop_loss           numeric(20,8),
  target              numeric(20,8),
  direction           text check (direction in ('long','short')),
  paper_trade_id      uuid references public.paper_trades(id) on delete set null,
  visibility          text not null default 'public' check (visibility in ('public','followers','league','private')),
  created_at          timestamptz not null default now()
);
create index if not exists reels_author_idx     on public.reels(author_id);
create index if not exists reels_created_at_idx on public.reels(created_at desc);
create index if not exists reels_symbol_idx     on public.reels(symbol);

-- back-fill the FK from paper_trades.source_reel_id now that reels exists
alter table public.paper_trades
  drop constraint if exists paper_trades_source_reel_fkey,
  add  constraint paper_trades_source_reel_fkey
    foreign key (source_reel_id) references public.reels(id) on delete set null;

-- ============================================================
-- reel_tags  (Instagram-style "tag people", but for indicators / patterns / strategies / tickers)
--   tag_type: indicator | pattern | strategy | ticker
--   x_pct, y_pct: position on the chart snapshot, 0–100 (NULL = chip-only, not pinned)
-- ============================================================
create table if not exists public.reel_tags (
  id          uuid primary key default gen_random_uuid(),
  reel_id     uuid not null references public.reels(id) on delete cascade,
  tag_type    text not null check (tag_type in ('indicator','pattern','strategy','ticker')),
  tag_value   text not null,
  x_pct       numeric(5,2),
  y_pct       numeric(5,2),
  ordinal     int not null default 0
);
create index if not exists reel_tags_reel_idx  on public.reel_tags(reel_id);
create index if not exists reel_tags_value_idx on public.reel_tags(tag_type, lower(tag_value));

-- ============================================================
-- reel_mirrors  (when another user copies a reel into their paper book)
-- ============================================================
create table if not exists public.reel_mirrors (
  id              uuid primary key default gen_random_uuid(),
  reel_id         uuid not null references public.reels(id) on delete cascade,
  mirrored_by     uuid not null references public.profiles(id) on delete cascade,
  paper_trade_id  uuid references public.paper_trades(id) on delete set null,
  sized_risk_pct  numeric(5,2),
  created_at      timestamptz not null default now()
);
create index if not exists reel_mirrors_reel_idx on public.reel_mirrors(reel_id);
create index if not exists reel_mirrors_user_idx on public.reel_mirrors(mirrored_by);

-- ============================================================
-- reel_engagement  (likes / saves / shares — count tracking)
-- ============================================================
create table if not exists public.reel_engagement (
  id          uuid primary key default gen_random_uuid(),
  reel_id     uuid not null references public.reels(id) on delete cascade,
  user_id     uuid not null references public.profiles(id) on delete cascade,
  kind        text not null check (kind in ('like','save','share','view')),
  created_at  timestamptz not null default now(),
  unique (reel_id, user_id, kind)
);
create index if not exists reel_engagement_reel_idx on public.reel_engagement(reel_id, kind);

-- ============================================================
-- holdings  (current open position per (owner, symbol) — derived from paper_trades)
-- View, not a table. Recomputed on every read.
-- ============================================================
create or replace view public.holdings_view as
  select
    owner_id,
    symbol,
    sum(case when side='buy'  then qty else 0 end) -
    sum(case when side='sell' then qty else 0 end) as net_qty,
    avg(entry_price) filter (where side='buy') as avg_entry,
    max(opened_at) as last_trade_at
  from public.paper_trades
  where status = 'open'
  group by owner_id, symbol;

-- ============================================================
-- follows  (social graph)
-- ============================================================
create table if not exists public.follows (
  follower_id uuid not null references public.profiles(id) on delete cascade,
  followee_id uuid not null references public.profiles(id) on delete cascade,
  created_at  timestamptz not null default now(),
  primary key (follower_id, followee_id)
);

-- ============================================================
-- leagues + league_members
-- ============================================================
create table if not exists public.leagues (
  id          uuid primary key default gen_random_uuid(),
  name        text not null,
  university  text,
  starts_at   timestamptz not null,
  ends_at     timestamptz,
  created_at  timestamptz not null default now()
);

create table if not exists public.league_members (
  league_id  uuid not null references public.leagues(id) on delete cascade,
  user_id    uuid not null references public.profiles(id) on delete cascade,
  joined_at  timestamptz not null default now(),
  primary key (league_id, user_id)
);

-- ============================================================
-- chart_layouts  (saved TradingView layouts per user — Task #2b)
-- ============================================================
create table if not exists public.chart_layouts (
  id          uuid primary key default gen_random_uuid(),
  owner_id    uuid not null references public.profiles(id) on delete cascade,
  name        text not null,
  symbol      text,
  resolution  text,
  layout      jsonb not null,
  created_at  timestamptz not null default now(),
  updated_at  timestamptz not null default now()
);

-- ============================================================
-- price_bars  (cached OHLCV for replay / fallback — Task #2b)
-- ============================================================
create table if not exists public.price_bars (
  symbol      text not null,
  resolution  text not null,
  t           timestamptz not null,
  o           numeric(20,8),
  h           numeric(20,8),
  l           numeric(20,8),
  c           numeric(20,8),
  v           numeric(20,8),
  primary key (symbol, resolution, t)
);

-- ============================================================
-- updated_at triggers
-- ============================================================
create or replace function public.tg_set_updated_at()
returns trigger language plpgsql as $$
begin new.updated_at = now(); return new; end;
$$;

drop trigger if exists profiles_updated_at on public.profiles;
create trigger profiles_updated_at before update on public.profiles
  for each row execute function public.tg_set_updated_at();

drop trigger if exists chart_layouts_updated_at on public.chart_layouts;
create trigger chart_layouts_updated_at before update on public.chart_layouts
  for each row execute function public.tg_set_updated_at();

-- ============================================================
-- RPC: email_for_username_login  (lets users log in with their username)
--
-- Naively translating username -> email would let anyone enumerate every
-- registered email address by trying a list of usernames. Instead this RPC
-- requires the caller to also supply the candidate password and verifies it
-- server-side against auth.users.encrypted_password (bcrypt via pgcrypto).
-- The email is returned ONLY when the credential pair is correct, so the
-- function discloses nothing an attacker does not already know.
--
-- Email logins skip this RPC entirely (the client passes the email straight
-- to signInWithPassword). The forgot-password flow also requires an email,
-- so this RPC is only used by the username-login path.
-- ============================================================
create or replace function public.email_for_username_login(p_username text, p_password text)
returns text
language plpgsql
security definer
set search_path = public, auth, extensions
as $$
declare
  candidate_email text;
  candidate_hash  text;
begin
  if p_username is null or length(trim(p_username)) < 3 then return null; end if;
  if p_password is null or length(p_password)        = 0 then return null; end if;

  select u.email, u.encrypted_password
    into candidate_email, candidate_hash
    from auth.users u
    join public.profiles p on p.id = u.id
   where lower(p.username) = lower(trim(p_username))
   limit 1;

  if candidate_email is null or candidate_hash is null then
    return null;
  end if;
  -- crypt() resolves via the function's search_path (public/extensions),
  -- whichever schema Supabase placed pgcrypto in.
  if crypt(p_password, candidate_hash) = candidate_hash then
    return candidate_email;
  end if;
  return null;
end;
$$;
grant execute on function public.email_for_username_login(text, text) to anon, authenticated;

-- Drop the older, leakier variant if it was ever created.
drop function if exists public.lookup_email_by_login(text);

-- ============================================================
-- RPC: seed_demo_users
-- One-shot seeder for the 8 legacy demo accounts so the existing demo logins
-- (e.g. liamos@... / demo1234) keep working against real Supabase Auth.
-- All passwords are stored as bcrypt hashes via pgcrypto, the same format
-- supabase-auth uses for real signups.
-- Call once after the migration:  select public.seed_demo_users();
-- Re-runnable: existing accounts are skipped.
-- ============================================================
create or replace function public.seed_demo_users()
returns text
language plpgsql
security definer
set search_path = public, auth, extensions
as $$
declare
  rec record;
  uid uuid;
  inserted int := 0;
  skipped  int := 0;
begin
  for rec in
    select * from (values
      ('alex.chen@student.unsw.edu.au', 'alexchen', 'student', 'UNSW',    'Student', 12, false),
      ('mia.lee@usyd.edu.au',           'mialee',   'student', 'USYD',    'Student',  9, false),
      ('jordan.kim@uts.edu.au',         'jkim',     'student', 'UTS',     'Student',  7, false),
      ('sarah.patel@monash.edu',        'sarahp',   'student', 'Monash',  'Student',  5, false),
      ('noah.brown@unimelb.edu.au',     'noahb',    'student', 'UniMelb', 'Student',  3, false),
      ('ella.smith@anu.edu.au',         'esmith',   'student', 'ANU',     'Student',  2, false),
      ('priya.shah@uq.edu.au',          'priya',    'student', 'UQ',      'Student',  2, false),
      ('liam.osullivan@gmail.com',      'liamos',   'public',  'Public',  'Pro',      1, true)
    ) as t(email, username, type, university, tier, days_ago, is_admin)
  loop
    if exists (select 1 from auth.users where lower(email) = lower(rec.email)) then
      skipped := skipped + 1;
      continue;
    end if;

    uid := gen_random_uuid();

    insert into auth.users (
      instance_id, id, aud, role, email,
      encrypted_password, email_confirmed_at,
      raw_app_meta_data, raw_user_meta_data,
      created_at, updated_at
    ) values (
      '00000000-0000-0000-0000-000000000000',
      uid, 'authenticated', 'authenticated', rec.email,
      crypt('demo1234', gen_salt('bf')),
      now() - (rec.days_ago || ' days')::interval,
      '{"provider":"email","providers":["email"]}'::jsonb,
      jsonb_build_object('username', rec.username, 'type', rec.type, 'university', rec.university),
      now() - (rec.days_ago || ' days')::interval, now()
    );

    insert into auth.identities (
      id, user_id, provider_id, provider, identity_data,
      last_sign_in_at, created_at, updated_at
    ) values (
      gen_random_uuid(), uid, uid::text, 'email',
      jsonb_build_object('sub', uid::text, 'email', rec.email),
      now() - (rec.days_ago || ' days')::interval,
      now() - (rec.days_ago || ' days')::interval, now()
    );

    insert into public.profiles (
      id, username, display_name, university, tier, type, bio,
      avatar_color, is_admin, badges, created_at
    ) values (
      uid, rec.username, initcap(rec.username), rec.university, rec.tier, rec.type,
      'Demo account · password is demo1234',
      '#' || substr(md5(rec.username), 1, 6),
      rec.is_admin,
      case when rec.is_admin then array['founder','admin'] else array['early-access'] end,
      now() - (rec.days_ago || ' days')::interval
    );

    inserted := inserted + 1;
  end loop;

  return format('Seeded %s users (%s skipped). Demo password: demo1234', inserted, skipped);
end;
$$;
revoke execute on function public.seed_demo_users() from public;

-- ============================================================
-- RPC: check_username_available
-- ============================================================
create or replace function public.check_username_available(p_username text)
returns boolean
language sql
security definer
set search_path = public
as $$
  select not exists (
    select 1 from public.profiles where lower(username) = lower(trim(p_username))
  );
$$;
grant execute on function public.check_username_available(text) to anon, authenticated;

-- ============================================================
-- RPC: check_email_available
-- An email is "available" if there's no profile yet for it.
-- (This lets users resume a half-finished signup where auth.users exists
--  but profiles does not.)
-- ============================================================
create or replace function public.check_email_available(p_email text)
returns boolean
language sql
security definer
set search_path = public, auth
as $$
  select not exists (
    select 1
      from auth.users u
      join public.profiles p on p.id = u.id
     where lower(u.email) = lower(trim(p_email))
  );
$$;
grant execute on function public.check_email_available(text) to anon, authenticated;

-- ============================================================
-- Helper: has_visibility(owner, field)
-- SECURITY DEFINER so it can read the owner's visibility_mask even when
-- the caller's RLS would forbid SELECT on the profile row.
-- ============================================================
create or replace function public.has_visibility(p_owner uuid, p_field text)
returns boolean
language sql
security definer
set search_path = public
as $$
  select coalesce((visibility_mask->>p_field)::boolean, false)
    from public.profiles where id = p_owner;
$$;
grant execute on function public.has_visibility(uuid, text) to anon, authenticated;

-- ============================================================
-- Admin-only RPC: list_registrations
-- Returns a registration summary for the admin page. Caller must have
-- profiles.is_admin = true.
-- ============================================================
create or replace function public.list_registrations()
returns table (
  email      text,
  username   text,
  university text,
  tier       text,
  type       text,
  is_admin   boolean,
  joined_at  timestamptz
)
language plpgsql
security definer
set search_path = public, auth
as $$
begin
  if not exists (select 1 from public.profiles where id = auth.uid() and is_admin = true) then
    raise exception 'Forbidden: admin only';
  end if;
  return query
    select u.email::text, p.username, p.university, p.tier, p.type, p.is_admin, p.created_at
      from public.profiles p
      join auth.users u on u.id = p.id
     order by p.created_at desc;
end;
$$;
grant execute on function public.list_registrations() to authenticated;

-- ============================================================
-- Row-Level Security
-- ============================================================
alter table public.profiles        enable row level security;
alter table public.strategies      enable row level security;
alter table public.paper_trades    enable row level security;
alter table public.reels           enable row level security;
alter table public.reel_tags       enable row level security;
alter table public.reel_mirrors    enable row level security;
alter table public.reel_engagement enable row level security;
alter table public.follows         enable row level security;
alter table public.leagues         enable row level security;
alter table public.league_members  enable row level security;
alter table public.chart_layouts   enable row level security;
alter table public.price_bars      enable row level security;

-- ----- profiles -----
-- Direct SELECT on the table is restricted to the owner, so that sensitive
-- columns (is_admin, visibility_mask, raw bio, etc.) are never exposed to
-- other users. The public-safe view `public_profiles` (defined below) is
-- what other clients should query when looking up someone else.
drop policy if exists profiles_read_all      on public.profiles;
drop policy if exists profiles_read_self     on public.profiles;
drop policy if exists profiles_insert_self   on public.profiles;
drop policy if exists profiles_update_self   on public.profiles;
drop policy if exists profiles_delete_self   on public.profiles;
create policy profiles_read_self    on public.profiles for select using (auth.uid() = id);
create policy profiles_insert_self  on public.profiles for insert with check (auth.uid() = id);
create policy profiles_update_self  on public.profiles for update using (auth.uid() = id) with check (auth.uid() = id);
create policy profiles_delete_self  on public.profiles for delete using (auth.uid() = id);

-- Public view: only the columns the task contract approves for the public
-- profile surface — username, display_name, tier, avatar_color, badges.
-- Granted to authenticated users only (NOT anon) so unauthenticated visitors
-- cannot enumerate the user list.
-- security_invoker = false means the view runs with the definer's privileges,
-- bypassing the self-only RLS on profiles for read-only purposes.
-- Drop any prior incarnation regardless of object type (regular view,
-- materialized view, or table) so the migration is safely re-runnable.
drop materialized view if exists public.public_profiles;
drop view              if exists public.public_profiles;
drop table             if exists public.public_profiles;
create view public.public_profiles
with (security_invoker = false) as
  select id, username, display_name, tier, avatar_color, badges
    from public.profiles;
revoke all on public.public_profiles from public;
grant select on public.public_profiles to authenticated;

-- ----- strategies -----
drop policy if exists strategies_read_all     on public.strategies;
drop policy if exists strategies_write_owner  on public.strategies;
create policy strategies_read_all    on public.strategies for select using (true);
create policy strategies_write_owner on public.strategies for all
  using (owner_id = auth.uid()) with check (owner_id = auth.uid());

-- ----- paper_trades -----
-- Owner sees everything. Others see only when the owner has opted-in (visibility_mask.holdings).
drop policy if exists paper_trades_read    on public.paper_trades;
drop policy if exists paper_trades_write   on public.paper_trades;
create policy paper_trades_read on public.paper_trades for select using (
  owner_id = auth.uid()
  or public.has_visibility(owner_id, 'holdings')
);
create policy paper_trades_write on public.paper_trades for all
  using (owner_id = auth.uid()) with check (owner_id = auth.uid());

-- ============================================================
-- holdings_view  (materialized roll-up of paper_trades)
-- One row per (owner_id, symbol) summarising open positions.
-- Note: PostgreSQL does NOT enforce RLS on materialized views, so direct
-- SELECT is revoked from regular users. Cross-user access goes through the
-- visibility-aware functions below; the materialized view itself is only
-- readable by service_role (and by the wrapper functions which run
-- SECURITY DEFINER). Refresh with: select public.refresh_holdings_view();
-- ============================================================
-- Drop any prior incarnation regardless of object type so the migration
-- can re-create holdings_view as a materialized view even when an earlier
-- iteration of the schema defined it as a regular view or a table.
drop materialized view if exists public.holdings_view;
drop view              if exists public.holdings_view;
drop table             if exists public.holdings_view;
create materialized view public.holdings_view as
  select
    owner_id,
    symbol,
    sum(case when side = 'buy' then qty else -qty end)             as net_qty,
    sum(case when side = 'buy' then qty * entry_price else 0 end)
      / nullif(sum(case when side = 'buy' then qty else 0 end), 0) as avg_cost,
    count(*) filter (where status = 'open')                        as open_legs,
    max(opened_at)                                                 as last_activity
  from public.paper_trades
  group by owner_id, symbol
  having sum(case when side = 'buy' then qty else -qty end) <> 0;

create unique index if not exists holdings_view_pk_idx
  on public.holdings_view (owner_id, symbol);
create index if not exists holdings_view_owner_idx
  on public.holdings_view (owner_id);

revoke all on public.holdings_view from public;
grant select on public.holdings_view to service_role;

create or replace function public.get_my_holdings()
returns setof public.holdings_view
language sql stable
security definer
set search_path = public
as $$
  select * from public.holdings_view where owner_id = auth.uid();
$$;
grant execute on function public.get_my_holdings() to authenticated;

create or replace function public.get_holdings_for(p_owner uuid)
returns setof public.holdings_view
language sql stable
security definer
set search_path = public
as $$
  select * from public.holdings_view
   where owner_id = p_owner
     and (p_owner = auth.uid() or public.has_visibility(p_owner, 'holdings'));
$$;
grant execute on function public.get_holdings_for(uuid) to authenticated;

-- NB: REFRESH MATERIALIZED VIEW CONCURRENTLY cannot run inside a function's
-- implicit transaction block, so the function uses a non-concurrent refresh.
-- For higher-traffic production use, drop this function and refresh via a
-- scheduled job (pg_cron) that calls REFRESH ... CONCURRENTLY directly.
create or replace function public.refresh_holdings_view()
returns void
language plpgsql
security definer
set search_path = public
as $$
begin
  refresh materialized view public.holdings_view;
end;
$$;
revoke execute on function public.refresh_holdings_view() from public;

-- ----- reels -----
drop policy if exists reels_read   on public.reels;
drop policy if exists reels_write  on public.reels;
create policy reels_read on public.reels for select using (
  visibility = 'public'
  or author_id = auth.uid()
  or (visibility = 'followers' and exists (
        select 1 from public.follows
         where follower_id = auth.uid() and followee_id = reels.author_id
      ))
);
create policy reels_write on public.reels for all
  using (author_id = auth.uid()) with check (author_id = auth.uid());

-- ----- reel_tags -----
drop policy if exists reel_tags_read  on public.reel_tags;
drop policy if exists reel_tags_write on public.reel_tags;
create policy reel_tags_read on public.reel_tags for select using (
  exists (select 1 from public.reels r where r.id = reel_tags.reel_id)
);
create policy reel_tags_write on public.reel_tags for all using (
  exists (select 1 from public.reels r where r.id = reel_tags.reel_id and r.author_id = auth.uid())
) with check (
  exists (select 1 from public.reels r where r.id = reel_tags.reel_id and r.author_id = auth.uid())
);

-- ----- reel_mirrors -----
drop policy if exists reel_mirrors_read  on public.reel_mirrors;
drop policy if exists reel_mirrors_write on public.reel_mirrors;
create policy reel_mirrors_read  on public.reel_mirrors for select using (true);
create policy reel_mirrors_write on public.reel_mirrors for all
  using (mirrored_by = auth.uid()) with check (mirrored_by = auth.uid());

-- ----- reel_engagement -----
drop policy if exists reel_engagement_read  on public.reel_engagement;
drop policy if exists reel_engagement_write on public.reel_engagement;
create policy reel_engagement_read  on public.reel_engagement for select using (true);
create policy reel_engagement_write on public.reel_engagement for all
  using (user_id = auth.uid()) with check (user_id = auth.uid());

-- ----- follows -----
drop policy if exists follows_read  on public.follows;
drop policy if exists follows_write on public.follows;
create policy follows_read  on public.follows for select using (true);
create policy follows_write on public.follows for all
  using (follower_id = auth.uid()) with check (follower_id = auth.uid());

-- ----- leagues -----
drop policy if exists leagues_read on public.leagues;
create policy leagues_read on public.leagues for select using (true);

-- ----- league_members -----
drop policy if exists league_members_read  on public.league_members;
drop policy if exists league_members_write on public.league_members;
create policy league_members_read  on public.league_members for select using (true);
create policy league_members_write on public.league_members for all
  using (user_id = auth.uid()) with check (user_id = auth.uid());

-- ----- chart_layouts -----
drop policy if exists chart_layouts_owner on public.chart_layouts;
create policy chart_layouts_owner on public.chart_layouts for all
  using (owner_id = auth.uid()) with check (owner_id = auth.uid());

-- ----- price_bars -----
-- Read-only cache, populated by Edge Function (service-role). Anyone can read.
drop policy if exists price_bars_read on public.price_bars;
create policy price_bars_read on public.price_bars for select using (true);

-- ============================================================
-- Done.
-- ============================================================

-- ===== 0002_profile_scorecard.sql =============================================
-- ============================================================
-- 0002_profile_scorecard.sql
--
-- Task #4 — Trader profile = quant scorecard with hybrid privacy.
--
-- Adds the visibility-aware accessors the new profile.html consumes,
-- a deterministic badge computation function, the follow-stats RPCs,
-- and tightens the paper_trades read policy so the holdings vs journal
-- visibility masks gate distinct slices of a trader's history:
--   - status='open'   → gated by visibility_mask.holdings
--   - status='closed' → gated by visibility_mask.journal
--
-- Re-runnable (every block uses CREATE OR REPLACE / DROP IF EXISTS).
-- ============================================================

-- ----- 1. Tighten paper_trades read policy ------------------------
--
-- Direct SELECT on paper_trades exposes the identifying columns (notes,
-- symbol, etc.). We let outsiders read open rows ONLY when the owner has
-- opted into `holdings`, and closed rows ONLY when `journal` is on.
-- Aggregate/derived metrics that don't reveal the journal narrative
-- (used to render the equity curve and quant tiles when ONLY the
-- equity_curve / metrics masks are on, but journal is off) flow through
-- a dedicated SECURITY DEFINER projection RPC further down.

drop policy if exists paper_trades_read    on public.paper_trades;
drop policy if exists paper_trades_write   on public.paper_trades;
create policy paper_trades_read on public.paper_trades for select using (
  owner_id = auth.uid()
  or (status = 'open'   and public.has_visibility(owner_id, 'holdings'))
  or (status = 'closed' and public.has_visibility(owner_id, 'journal'))
);
create policy paper_trades_write on public.paper_trades for all
  using (owner_id = auth.uid()) with check (owner_id = auth.uid());

-- ----- 1b. Tighten strategies read policy -------------------------
--
-- The base table previously had `strategies_read_all` which let any
-- authenticated user enumerate every other user's strategy library
-- regardless of their visibility_mask.strategies setting. We restrict
-- to (owner | strategies-mask-on) here so the wrapper RPC and direct
-- SELECT enforce the same gate.

drop policy if exists strategies_read_all     on public.strategies;
drop policy if exists strategies_read         on public.strategies;
drop policy if exists strategies_write_owner  on public.strategies;
create policy strategies_read on public.strategies for select using (
  owner_id = auth.uid()
  or public.has_visibility(owner_id, 'strategies')
);
create policy strategies_write_owner on public.strategies for all
  using (owner_id = auth.uid()) with check (owner_id = auth.uid());

-- ----- 2. Profile lookup by username (visibility-stripped) -------
--
-- Returns the public columns plus the owner's visibility_mask so the
-- client can decide which sub-cards to render. Sensitive columns
-- (is_admin, raw bio when private, etc.) are NOT exposed.

create or replace function public.get_profile_card(p_username text)
returns table (
  id              uuid,
  username        text,
  display_name    text,
  tier            text,
  type            text,
  university      text,   -- nulled out when visibility_mask.university = false (and viewer is not owner)
  bio             text,
  avatar_color    text,
  badges          text[],
  visibility_mask jsonb,
  joined_at       timestamptz
)
language sql stable
security definer
set search_path = public
as $$
  select
    p.id,
    p.username,
    p.display_name,
    p.tier,
    p.type,
    case
      when p.id = auth.uid() then p.university
      when coalesce((p.visibility_mask->>'university')::boolean, true) then p.university
      else null
    end as university,
    p.bio,
    p.avatar_color,
    p.badges,
    p.visibility_mask,
    p.created_at
  from public.profiles p
  where lower(p.username) = lower(trim(p_username))
  limit 1;
$$;
revoke all on function public.get_profile_card(text) from public;
grant execute on function public.get_profile_card(text) to authenticated;

-- ----- 3. Closed-trade journal accessor --------------------------
--
-- Visibility-gated server-side accessor for the Journal tab. Returns
-- the closed paper_trades for an owner only when:
--   - the caller IS the owner, OR
--   - the owner has visibility_mask.journal = true.

create or replace function public.get_journal_for(p_owner uuid)
returns setof public.paper_trades
language sql stable
security definer
set search_path = public
as $$
  select *
    from public.paper_trades
   where owner_id = p_owner
     and status = 'closed'
     and (p_owner = auth.uid() or public.has_visibility(p_owner, 'journal'))
   order by closed_at desc nulls last, opened_at desc;
$$;
revoke all on function public.get_journal_for(uuid) from public;
grant execute on function public.get_journal_for(uuid) to authenticated;

-- ----- 3b. Performance-only projection ---------------------------
--
-- Returns the *minimum* fields the client needs to compute equity
-- curve + quant tiles (no `notes`, no `source_reel_id`, no `target` —
-- nothing journal-specific). Gated by `metrics OR equity_curve` so
-- a trader can publish their performance without revealing the
-- narrative behind each trade. Owner always sees their own data.

create or replace function public.get_perf_trades_for(p_owner uuid)
returns table (
  id          uuid,
  symbol      text,
  side        text,
  qty         numeric,
  entry_price numeric,
  exit_price  numeric,
  stop_loss   numeric,
  status      text,
  opened_at   timestamptz,
  closed_at   timestamptz
)
language sql stable
security definer
set search_path = public
as $$
  select pt.id, pt.symbol, pt.side, pt.qty,
         pt.entry_price, pt.exit_price, pt.stop_loss,
         pt.status, pt.opened_at, pt.closed_at
    from public.paper_trades pt
   where pt.owner_id = p_owner
     and pt.status   = 'closed'
     and (
       p_owner = auth.uid()
       or public.has_visibility(p_owner, 'metrics')
       or public.has_visibility(p_owner, 'equity_curve')
     )
   order by pt.closed_at asc nulls last;
$$;
revoke all on function public.get_perf_trades_for(uuid) from public;
grant execute on function public.get_perf_trades_for(uuid) to authenticated;

-- ----- 4. Strategies accessor (visibility-gated) -----------------
--
-- Today RLS on strategies is `read_all`, but the profile page only
-- shows them on the Strategies tab when visibility_mask.strategies =
-- true. This wrapper gives the client a single source of truth for
-- that gate without changing the global RLS contract (other surfaces
-- like the reel composer still read the table directly).

create or replace function public.get_strategies_for(p_owner uuid)
returns setof public.strategies
language sql stable
security definer
set search_path = public
as $$
  select *
    from public.strategies
   where owner_id = p_owner
     and (p_owner = auth.uid() or public.has_visibility(p_owner, 'strategies'))
   order by created_at desc;
$$;
revoke all on function public.get_strategies_for(uuid) from public;
grant execute on function public.get_strategies_for(uuid) to authenticated;

-- ----- 5. Follow graph helpers -----------------------------------

create or replace function public.get_follow_stats(p_owner uuid)
returns table (followers bigint, following bigint)
language sql stable
security definer
set search_path = public
as $$
  select
    (select count(*) from public.follows where followee_id = p_owner) as followers,
    (select count(*) from public.follows where follower_id = p_owner) as following;
$$;
revoke all on function public.get_follow_stats(uuid) from public;
grant execute on function public.get_follow_stats(uuid) to authenticated;

create or replace function public.am_following(p_target uuid)
returns boolean
language sql stable
security definer
set search_path = public
as $$
  select exists (
    select 1 from public.follows
     where follower_id = auth.uid() and followee_id = p_target
  );
$$;
revoke all on function public.am_following(uuid) from public;
grant execute on function public.am_following(uuid) to authenticated;

create or replace function public.follow_user(p_target uuid)
returns void
language sql
security definer
set search_path = public
as $$
  insert into public.follows (follower_id, followee_id)
  values (auth.uid(), p_target)
  on conflict do nothing;
$$;
revoke all on function public.follow_user(uuid) from public;
grant execute on function public.follow_user(uuid) to authenticated;

create or replace function public.unfollow_user(p_target uuid)
returns void
language sql
security definer
set search_path = public
as $$
  delete from public.follows
   where follower_id = auth.uid()
     and followee_id = p_target;
$$;
revoke all on function public.unfollow_user(uuid) from public;
grant execute on function public.unfollow_user(uuid) to authenticated;

-- ============================================================
-- 6. Badges
--
-- Auto-issued on demand. Returns the union of:
--   - 100+ trades       — closed_trades >= 100
--   - 6 profitable mo   — at least 6 calendar months with positive net P&L
--   - top_sharpe_q3_26  — sharpe ratio rank in top 1% (computed against
--                         everyone with >= 30 closed trades) for the
--                         current quarter window. We approximate: badge
--                         is granted when sharpe >= 2.5 AND closed >= 30.
--                         (A real cron job replaces this with rank = 1.)
--   - mirror_master     — 50+ mirrors of this owner's reels
--   - strategy_curator  — 5+ published strategies
--
-- All inputs come from existing tables; no extra schema is required.
-- ============================================================

create or replace function public.compute_badges_for(p_owner uuid)
returns text[]
language plpgsql stable
security definer
set search_path = public
as $$
declare
  out_badges text[] := '{}';
  closed_n   int;
  profit_mo  int;
  sharpe_n   numeric;
  mirror_n   int;
  strat_n    int;
begin
  -- closed-trade count
  select count(*) into closed_n
    from public.paper_trades
   where owner_id = p_owner and status = 'closed';
  if closed_n >= 100 then
    out_badges := array_append(out_badges, '100_trades');
  end if;

  -- profitable months
  select count(*) into profit_mo from (
    select date_trunc('month', closed_at) as m,
           sum((coalesce(exit_price,0) - entry_price) * qty * case when side='buy' then 1 else -1 end) as pnl
      from public.paper_trades
     where owner_id = p_owner and status='closed' and closed_at is not null
     group by 1
    having sum((coalesce(exit_price,0) - entry_price) * qty * case when side='buy' then 1 else -1 end) > 0
  ) sub;
  if profit_mo >= 6 then
    out_badges := array_append(out_badges, '6_profitable_months');
  end if;

  -- approximate top-sharpe (cron will replace with true rank-1 query)
  if closed_n >= 30 then
    -- naive realised-pnl-per-trade std/mean as a proxy
    select case
             when stddev_samp(pnl) is null or stddev_samp(pnl) = 0 then null
             else avg(pnl) / stddev_samp(pnl) * sqrt(252)
           end into sharpe_n
      from (
        select (coalesce(exit_price,0) - entry_price) * qty * case when side='buy' then 1 else -1 end as pnl
          from public.paper_trades
         where owner_id = p_owner and status='closed'
      ) p;
    if sharpe_n is not null and sharpe_n >= 2.5 then
      out_badges := array_append(out_badges, 'top_sharpe_q3_26');
    end if;
  end if;

  -- mirror master
  select count(*) into mirror_n
    from public.reel_mirrors m
    join public.reels r on r.id = m.reel_id
   where r.author_id = p_owner;
  if mirror_n >= 50 then
    out_badges := array_append(out_badges, 'mirror_master');
  end if;

  -- strategy curator
  select count(*) into strat_n
    from public.strategies
   where owner_id = p_owner;
  if strat_n >= 5 then
    out_badges := array_append(out_badges, 'strategy_curator');
  end if;

  return out_badges;
end;
$$;
revoke all on function public.compute_badges_for(uuid) from public;
grant execute on function public.compute_badges_for(uuid) to authenticated;


-- ============================================================
-- 7. Cash balance accessor
--
-- The profile page shows a "Cash buffer" line whose visibility is
-- gated **only** by visibility_mask.cash. Computing it client-side
-- from get_perf_trades_for + holdings would conflate the cash mask
-- with the metrics / holdings masks (a trader with cash=true but
-- metrics=false would see a fabricated number). This RPC computes
-- it server-side and ignores every other mask.
--
-- Convention: starting capital is $100,000.
--   cash = 100000
--        + Σ realised P&L on closed trades
--        − Σ cost basis of currently open long positions
-- ============================================================

create or replace function public.get_cash_balance_for(p_owner uuid)
returns numeric
language sql stable
security definer
set search_path = public
as $$
  with realised as (
    select coalesce(sum(
      (coalesce(exit_price, 0) - entry_price) * qty *
      case when side = 'buy' then 1 else -1 end
    ), 0) as pnl
      from public.paper_trades
     where owner_id = p_owner
       and status = 'closed'
  ),
  open_cost as (
    -- Cost basis of currently-open long positions. We compute this
    -- directly from paper_trades rather than the materialised view
    -- so a stale refresh doesn't drift cash.
    select coalesce(sum(
      case when side = 'buy' then qty * entry_price else 0 end
      - case when side = 'sell' then qty * entry_price else 0 end
    ), 0) as cost
      from public.paper_trades
     where owner_id = p_owner
       and status = 'open'
  )
  select case
    when p_owner = auth.uid()
      or public.has_visibility(p_owner, 'cash')
    then 100000::numeric + (select pnl from realised) - (select cost from open_cost)
    else null
  end;
$$;
revoke all on function public.get_cash_balance_for(uuid) from public;
grant execute on function public.get_cash_balance_for(uuid) to authenticated;

-- ===== 0003_reels_engine.sql ==================================================
-- ============================================================
--  TradeArena · 0003_reels_engine.sql
--  ----------------------------------------------------------
--  Server side of Task #5 — strategy reels feed + composer.
--
--  All client-facing access goes through SECURITY DEFINER RPCs
--  that wrap the RLS-protected base tables, so we can:
--    1. atomically open paper trades when a reel is published,
--    2. enforce visibility (public / followers / private) in
--       a single hardened code path, and
--    3. return rich, joined payloads in one round-trip without
--       leaking columns the row-level policies would otherwise
--       expose to followers.
--
--  Conventions:
--    - Default account size is $100,000 (matches profile.html).
--    - Default risk per reel is 1% of account.
--    - Position sizing: qty = (account * risk_pct/100) / |entry-stop|
--      (signed by direction = long => +qty, short => -qty).
--
--  Apply order: 0001 → 0002 → 0003.
-- ============================================================

set search_path = public;

-- ============================================================
-- 1. Tighten reel_engagement & reel_mirrors read policies
--
-- 0001 left these as `using (true)` so that aggregate counts
-- (likes / saves / mirrors) could be computed by anyone. That's
-- still the goal — but enumerating *who* liked a reel is a
-- different question. We keep table-level reads open so the
-- counts queries below stay simple, but we expose viewer-only
-- detail through the RPCs (no rows returned for "who saved").
-- ============================================================
-- (no-op DDL, kept here as a documentation anchor)


-- ============================================================
-- 2. Helper: position sizing
--
-- Risk-based sizing — qty is whatever quantity makes
-- |entry - stop| * qty == account * risk_pct/100. The math
-- lives in SQL (not just JS) so the auto-open trade on publish
-- and the manual mirror open use exactly the same formula.
-- Returns 0 when the price levels make no sense (entry == stop,
-- negative entry, etc.).
-- ============================================================
create or replace function public.tarena_position_size(
  p_entry        numeric,
  p_stop         numeric,
  p_risk_pct     numeric,
  p_account_size numeric
)
returns numeric
language sql immutable
as $$
  -- Truncate (floor) to 6 decimals — must match assets/reels.js
  -- positionSize() exactly. Banker's rounding in SQL `round()` and
  -- JS `toFixed()` disagree at the 6th-decimal boundary, which could
  -- otherwise show one qty in the composer preview and store a
  -- different one server-side.
  select case
    when coalesce(p_entry, 0) <= 0
      or coalesce(p_stop,  0) <= 0
      or coalesce(p_risk_pct, 0) <= 0
      or coalesce(p_account_size, 0) <= 0
      or abs(p_entry - p_stop) < 1e-9
    then 0::numeric
    else floor(
      ((p_account_size * (p_risk_pct / 100.0)) / abs(p_entry - p_stop)) * 1000000
    ) / 1000000.0
  end;
$$;
grant execute on function public.tarena_position_size(numeric, numeric, numeric, numeric) to authenticated;


-- ============================================================
-- 3. Helper: can the current viewer read this reel?
--
-- Mirrors `reels_read` policy logic but exposed as a function so
-- the SECURITY DEFINER RPCs below can short-circuit cleanly.
-- 'league' visibility is treated as **private until leagues ship**
-- so a user who picks "League only" today never accidentally
-- broadcasts publicly when leagues launch with different rules.
-- ============================================================
create or replace function public.can_read_reel(
  p_visibility text,
  p_author_id  uuid
)
returns boolean
language sql stable
security definer
set search_path = public
as $$
  select case
    when p_visibility = 'public'                      then true
    when p_author_id  = auth.uid()                    then true
    when p_visibility = 'followers' then exists (
      select 1 from public.follows
       where follower_id = auth.uid()
         and followee_id = p_author_id
    )
    else false
  end;
$$;
revoke all on function public.can_read_reel(text, uuid) from public;
grant execute on function public.can_read_reel(text, uuid) to authenticated;


-- ============================================================
-- 4. publish_reel(p_payload jsonb)
--
-- Atomic publish path — the *only* way the client should
-- create reels. Inserts the reel row, the tag rows, opens a
-- paper trade sized to risk_pct of the author's account, and
-- back-links the trade onto the reel — all in one transaction.
--
-- Payload shape:
--   {
--     "symbol":     "BHP.AX",
--     "market":     "asx",
--     "thesis":     "...",                         -- <= 280 chars
--     "direction":  "long" | "short",
--     "entry":      43.50,
--     "stop_loss":  41.80,
--     "target":     48.20,
--     "visibility": "public"|"followers"|"private",
--     "snapshot":   "data:image/png;base64,...",   -- nullable
--     "risk_pct":   1.0,                           -- defaults to 1
--     "tags": [
--       { "tag_type": "indicator", "tag_value": "RSI",
--         "x_pct": 35.0, "y_pct": 70.5, "ordinal": 0 },
--       ...
--     ]
--   }
--
-- Returns: reel_id uuid.
-- ============================================================
create or replace function public.publish_reel(p_payload jsonb)
returns uuid
language plpgsql
security definer
set search_path = public
as $$
declare
  v_uid       uuid := auth.uid();
  v_reel_id   uuid;
  v_trade_id  uuid;
  v_qty       numeric;
  v_thesis    text;
  v_visibility text;
  v_direction text;
  v_entry     numeric;
  v_live      numeric;   -- last quote at publish time (used for paper_trades.entry_price)
  v_fill      numeric;   -- price the auto trade actually fills at
  v_stop      numeric;
  v_target    numeric;
  v_risk_pct  numeric;
  v_account   numeric := 100000.0;  -- v1 starting capital
  v_tag       jsonb;
begin
  if v_uid is null then
    raise exception 'Not authenticated';
  end if;

  v_thesis     := nullif(trim(p_payload->>'thesis'), '');
  v_direction  := lower(coalesce(p_payload->>'direction', 'long'));
  v_visibility := lower(coalesce(p_payload->>'visibility', 'public'));
  v_entry      := nullif((p_payload->>'entry'),      '')::numeric;
  v_live       := nullif((p_payload->>'live_price'), '')::numeric;
  v_stop       := nullif((p_payload->>'stop_loss'),  '')::numeric;
  v_target     := nullif((p_payload->>'target'),     '')::numeric;
  v_risk_pct   := coalesce(nullif((p_payload->>'risk_pct'), '')::numeric, 1.0);

  if v_thesis is null then raise exception 'Thesis is required'; end if;
  if length(v_thesis) > 280 then raise exception 'Thesis exceeds 280 characters'; end if;
  if v_direction not in ('long','short') then
    raise exception 'Direction must be long or short';
  end if;
  if v_visibility not in ('public','followers','league','private') then
    raise exception 'Bad visibility';
  end if;
  if coalesce(p_payload->>'symbol', '') = '' then
    raise exception 'Symbol is required';
  end if;
  if v_entry is null or v_entry <= 0 then
    raise exception 'Entry price is required';
  end if;
  if v_stop is null or v_stop <= 0 then
    raise exception 'Stop loss is required';
  end if;
  if v_risk_pct < 0.05 or v_risk_pct > 25 then
    raise exception 'risk_pct out of range (0.05..25)';
  end if;

  -- 4a. Insert the reel
  insert into public.reels (
    author_id, symbol, market, chart_snapshot_url,
    thesis, entry, stop_loss, target, direction, visibility
  ) values (
    v_uid,
    p_payload->>'symbol',
    nullif(p_payload->>'market', ''),
    nullif(p_payload->>'snapshot', ''),
    v_thesis,
    v_entry, v_stop, v_target,
    v_direction,
    v_visibility
  )
  returning id into v_reel_id;

  -- 4b. Insert tags (skip silently when payload omits them)
  if jsonb_typeof(p_payload->'tags') = 'array' then
    for v_tag in select * from jsonb_array_elements(p_payload->'tags') loop
      if (v_tag->>'tag_type') in ('indicator','pattern','strategy','ticker')
         and coalesce(v_tag->>'tag_value', '') <> ''
      then
        insert into public.reel_tags (
          reel_id, tag_type, tag_value, x_pct, y_pct, ordinal
        ) values (
          v_reel_id,
          v_tag->>'tag_type',
          v_tag->>'tag_value',
          nullif(v_tag->>'x_pct','')::numeric,
          nullif(v_tag->>'y_pct','')::numeric,
          coalesce(nullif(v_tag->>'ordinal','')::int, 0)
        );
      end if;
    end loop;
  end if;

  -- 4c. Auto paper trade — risk-sized, opens silently at LIVE PRICE.
  -- The reel itself stores the user's intended `entry` (for the chart
  -- annotation and R:R math), but the back-linked paper_trade fills
  -- at the live quote the client captured immediately before posting.
  -- We fall back to the user-typed entry only when the client didn't
  -- send a live snapshot — keeps the function backwards-compatible
  -- if a future caller skips the field.
  v_fill := coalesce(v_live, v_entry);
  v_qty  := public.tarena_position_size(v_entry, v_stop, v_risk_pct, v_account);
  if v_qty > 0 then
    insert into public.paper_trades (
      owner_id, symbol, market, side, qty,
      entry_price, stop_loss, target,
      status, source_reel_id
    ) values (
      v_uid,
      p_payload->>'symbol',
      nullif(p_payload->>'market', ''),
      case when v_direction = 'long' then 'buy' else 'sell' end,
      v_qty,
      v_fill, v_stop, v_target,
      'open', v_reel_id
    )
    returning id into v_trade_id;

    update public.reels
       set paper_trade_id = v_trade_id
     where id = v_reel_id;
  end if;

  return v_reel_id;
end;
$$;
revoke all on function public.publish_reel(jsonb) from public;
grant execute on function public.publish_reel(jsonb) to authenticated;


-- ============================================================
-- 5. mirror_reel(p_reel_id, p_risk_pct, p_account_size)
--
-- Opens a paper trade in the *viewer's* account, sized to their
-- own risk %, and records a reel_mirrors row linking it back to
-- the source reel. Idempotent on (reel_id, mirrored_by) — second
-- press returns the existing row instead of erroring.
-- ============================================================
create or replace function public.mirror_reel(
  p_reel_id      uuid,
  p_risk_pct     numeric default 1.0,
  p_account_size numeric default 100000.0,
  p_live_price   numeric default null     -- viewer's live quote at click time
)
returns uuid
language plpgsql
security definer
set search_path = public
as $$
declare
  v_uid      uuid := auth.uid();
  v_reel     public.reels%rowtype;
  v_qty      numeric;
  v_fill     numeric;
  v_trade_id uuid;
  v_mirror_id uuid;
  v_existing  uuid;
begin
  if v_uid is null then raise exception 'Not authenticated'; end if;
  if p_risk_pct is null or p_risk_pct < 0.05 or p_risk_pct > 25 then
    raise exception 'risk_pct out of range (0.05..25)';
  end if;

  select * into v_reel from public.reels where id = p_reel_id;
  if not found then raise exception 'Reel not found'; end if;

  if not public.can_read_reel(v_reel.visibility, v_reel.author_id) then
    raise exception 'You cannot mirror this reel';
  end if;

  if v_reel.author_id = v_uid then
    raise exception 'You can''t mirror your own reel';
  end if;

  -- Idempotency
  select id into v_existing
    from public.reel_mirrors
   where reel_id = p_reel_id and mirrored_by = v_uid
   limit 1;
  if v_existing is not null then return v_existing; end if;

  v_qty := public.tarena_position_size(v_reel.entry, v_reel.stop_loss, p_risk_pct, p_account_size);
  if v_qty <= 0 then
    raise exception 'Cannot size position from this reel';
  end if;

  -- Mirror trades fill at the viewer's live quote (matches publish_reel
  -- semantics — neither caller is allowed to backdate the fill price).
  v_fill := coalesce(p_live_price, v_reel.entry);

  insert into public.paper_trades (
    owner_id, symbol, market, side, qty,
    entry_price, stop_loss, target,
    status, source_reel_id
  ) values (
    v_uid,
    v_reel.symbol, v_reel.market,
    case when v_reel.direction = 'long' then 'buy' else 'sell' end,
    v_qty,
    v_fill, v_reel.stop_loss, v_reel.target,
    'open', v_reel.id
  )
  returning id into v_trade_id;

  insert into public.reel_mirrors (
    reel_id, mirrored_by, paper_trade_id, sized_risk_pct
  ) values (
    p_reel_id, v_uid, v_trade_id, p_risk_pct
  )
  returning id into v_mirror_id;

  return v_mirror_id;
end;
$$;
-- Drop the old 3-arg signature in case this migration is re-run after
-- an earlier deploy of 0003 that didn't include p_live_price.
drop function if exists public.mirror_reel(uuid, numeric, numeric);
revoke all on function public.mirror_reel(uuid, numeric, numeric, numeric) from public;
grant execute on function public.mirror_reel(uuid, numeric, numeric, numeric) to authenticated;


-- ============================================================
-- 6. toggle_engagement(p_reel_id, p_kind)
--
-- Like / save / share toggle. 'view' is also acceptable (counted
-- once per (reel, user) thanks to the unique constraint). Returns
-- the resulting state ({on: bool, count: int}) so the client can
-- update the chip without a follow-up read.
-- ============================================================
create or replace function public.toggle_engagement(
  p_reel_id uuid,
  p_kind    text
)
returns jsonb
language plpgsql
security definer
set search_path = public
as $$
declare
  v_uid    uuid := auth.uid();
  v_exists uuid;
  v_count  bigint;
  v_now_on boolean;
begin
  if v_uid is null then raise exception 'Not authenticated'; end if;
  if p_kind not in ('like','save','share','view') then
    raise exception 'Bad engagement kind';
  end if;

  -- Visibility gate — can the viewer even see this reel?
  if not exists (
    select 1 from public.reels r
     where r.id = p_reel_id
       and public.can_read_reel(r.visibility, r.author_id)
  ) then
    raise exception 'Cannot engage with this reel';
  end if;

  select id into v_exists
    from public.reel_engagement
   where reel_id = p_reel_id and user_id = v_uid and kind = p_kind
   limit 1;

  if p_kind in ('share','view') then
    -- Non-toggleable kinds — insert if missing, leave alone otherwise.
    if v_exists is null then
      insert into public.reel_engagement (reel_id, user_id, kind)
        values (p_reel_id, v_uid, p_kind);
    end if;
    v_now_on := true;
  else
    if v_exists is null then
      insert into public.reel_engagement (reel_id, user_id, kind)
        values (p_reel_id, v_uid, p_kind);
      v_now_on := true;
    else
      delete from public.reel_engagement where id = v_exists;
      v_now_on := false;
    end if;
  end if;

  select count(*) into v_count
    from public.reel_engagement
   where reel_id = p_reel_id and kind = p_kind;

  return jsonb_build_object('on', v_now_on, 'count', v_count, 'kind', p_kind);
end;
$$;
revoke all on function public.toggle_engagement(uuid, text) from public;
grant execute on function public.toggle_engagement(uuid, text) to authenticated;


-- ============================================================
-- 7. feed_reels(...)
--
-- The single read-side query for the reels feed. Returns one row
-- per reel, with author profile + tag list + engagement counts +
-- viewer's own engagement state + the linked paper trade fields
-- needed to render entry/SL/target and live P&L locally.
--
-- Tabs:
--   'fy'         — chronological reverse, all visible reels
--   'following'  — only authors the viewer follows
--   'trending'   — engagement-weighted in the last 24h
--
-- Filters (optional, all default null):
--   p_tag    — exact tag_value match (any tag_type)
--   p_ticker — exact symbol match  (fed by `$TICKER` in the search box)
--   p_user   — exact author username match (fed by `@user` in the search box)
--   p_q      — substring match against thesis or tag_value
--
-- Cursor: any reel where created_at < p_cursor (NULL = first page).
-- ============================================================
-- Drop the older 6-arg signature so re-running the migration after a
-- previous deploy doesn't leave two ambiguous overloads.
drop function if exists public.feed_reels(timestamptz, int, text, text, text, text);
create or replace function public.feed_reels(
  p_cursor   timestamptz default null,
  p_limit    int         default 12,
  p_tab      text        default 'fy',
  p_tag      text        default null,
  p_ticker   text        default null,
  p_q        text        default null,
  p_user     text        default null
)
returns jsonb
language plpgsql
stable
security definer
set search_path = public
as $$
declare
  v_uid    uuid := auth.uid();
  v_limit  int  := least(greatest(coalesce(p_limit, 12), 1), 30);
  v_rows   jsonb;
begin
  with base as (
    select r.*
      from public.reels r
     where public.can_read_reel(r.visibility, r.author_id)
       and (p_cursor is null or r.created_at < p_cursor)
       and (p_tab <> 'following' or exists (
            select 1 from public.follows f
             where f.follower_id = v_uid and f.followee_id = r.author_id))
       and (p_tag is null or exists (
            select 1 from public.reel_tags t
             where t.reel_id = r.id and lower(t.tag_value) = lower(p_tag)))
       and (p_ticker is null or lower(r.symbol) = lower(p_ticker))
       and (p_user is null or exists (
            select 1 from public.public_profiles pp
             where pp.id = r.author_id
               and lower(pp.username) = lower(p_user)))
       and (p_q is null or
            r.thesis ilike '%' || p_q || '%' or
            exists (select 1 from public.reel_tags t
                     where t.reel_id = r.id
                       and lower(t.tag_value) ilike '%' || lower(p_q) || '%'))
  ),
  scored as (
    select
      b.*,
      case when p_tab = 'trending'
        then coalesce((select count(*) from public.reel_engagement e
                        where e.reel_id = b.id
                          and e.created_at >= now() - interval '24 hours'), 0)
        else 0
      end as score
    from base b
  ),
  ranked as (
    select s.*
      from scored s
     order by
       case when p_tab = 'trending' then s.score end desc nulls last,
       s.created_at desc
     limit v_limit + 1
  ),
  tag_lists as (
    select t.reel_id, jsonb_agg(jsonb_build_object(
      'tag_type', t.tag_type,
      'tag_value', t.tag_value,
      'x_pct', t.x_pct,
      'y_pct', t.y_pct,
      'ordinal', t.ordinal
    ) order by t.ordinal, t.id) as tags
      from public.reel_tags t
     where t.reel_id in (select id from ranked)
     group by t.reel_id
  ),
  eng_counts as (
    select e.reel_id,
           coalesce(sum((e.kind='like' )::int), 0) as likes,
           coalesce(sum((e.kind='save' )::int), 0) as saves,
           coalesce(sum((e.kind='share')::int), 0) as shares,
           coalesce(sum((e.kind='view' )::int), 0) as views
      from public.reel_engagement e
     where e.reel_id in (select id from ranked)
     group by e.reel_id
  ),
  mirror_counts as (
    select m.reel_id, count(*) as mirrors
      from public.reel_mirrors m
     where m.reel_id in (select id from ranked)
     group by m.reel_id
  ),
  viewer_eng as (
    select e.reel_id,
           bool_or(e.kind='like') as liked,
           bool_or(e.kind='save') as saved
      from public.reel_engagement e
     where e.user_id = v_uid
       and e.reel_id in (select id from ranked)
     group by e.reel_id
  ),
  viewer_mirror as (
    select m.reel_id, true as mirrored
      from public.reel_mirrors m
     where m.mirrored_by = v_uid
       and m.reel_id in (select id from ranked)
  ),
  -- Author win rate from closed paper trades. Long wins when exit > entry,
  -- short wins when exit < entry. Returns null when the author has no
  -- closed trades yet (UI shows "—" rather than "0%").
  author_stats as (
    select pt.owner_id,
           count(*) filter (where pt.status = 'closed')                      as closed_n,
           round(100.0 * count(*) filter (
             where pt.status = 'closed'
               and ((pt.side = 'buy'  and pt.exit_price > pt.entry_price)
                 or (pt.side = 'sell' and pt.exit_price < pt.entry_price))
           )::numeric / nullif(count(*) filter (where pt.status = 'closed'), 0), 1) as win_rate
      from public.paper_trades pt
     where pt.owner_id in (select author_id from ranked)
     group by pt.owner_id
  ),
  viewer_follow as (
    select f.followee_id, true as following
      from public.follows f
     where f.follower_id = v_uid
       and f.followee_id in (select author_id from ranked)
  ),
  trade_qty as (
    select pt.id as paper_trade_id, pt.qty, pt.side, pt.entry_price
      from public.paper_trades pt
     where pt.id in (select paper_trade_id from ranked where paper_trade_id is not null)
  ),
  joined as (
    select
      r.id, r.symbol, r.market, r.chart_snapshot_url,
      r.thesis, r.entry, r.stop_loss, r.target, r.direction,
      r.visibility, r.created_at, r.paper_trade_id,
      tq.qty         as paper_trade_qty,
      tq.side        as paper_trade_side,
      tq.entry_price as paper_trade_entry,
      jsonb_build_object(
        'id',           p.id,
        'username',     p.username,
        'display_name', p.display_name,
        'tier',         p.tier,
        'avatar_color', p.avatar_color,
        'win_rate',     ast.win_rate,
        'closed_n',     coalesce(ast.closed_n, 0)
      ) as author,
      coalesce(tl.tags, '[]'::jsonb) as tags,
      jsonb_build_object(
        'likes',   coalesce(ec.likes,   0),
        'saves',   coalesce(ec.saves,   0),
        'shares',  coalesce(ec.shares,  0),
        'views',   coalesce(ec.views,   0),
        'mirrors', coalesce(mc.mirrors, 0)
      ) as counts,
      jsonb_build_object(
        'liked',     coalesce(ve.liked,    false),
        'saved',     coalesce(ve.saved,    false),
        'mirrored',  coalesce(vm.mirrored, false),
        'following', coalesce(vf.following, false)
      ) as viewer_state
    from ranked r
    join public.profiles p     on p.id = r.author_id
    left join tag_lists tl     on tl.reel_id    = r.id
    left join eng_counts ec    on ec.reel_id    = r.id
    left join mirror_counts mc on mc.reel_id    = r.id
    left join viewer_eng ve    on ve.reel_id    = r.id
    left join viewer_mirror vm on vm.reel_id    = r.id
    left join author_stats ast on ast.owner_id  = r.author_id
    left join viewer_follow vf on vf.followee_id = r.author_id
    left join trade_qty   tq   on tq.paper_trade_id = r.paper_trade_id
  ),
  -- We pulled v_limit+1 rows in `ranked` so we can tell whether
  -- there's a next page. `page` keeps only the first v_limit; the
  -- extra row (if present) signals "more rows exist" without ever
  -- shipping it to the client. next_cursor = oldest created_at on
  -- the trimmed page, set only when an extra row exists. If two
  -- reels share an exact created_at across a page boundary the
  -- second one is briefly skipped — acceptable for v1 (resolved on
  -- next refresh) and avoids a composite-cursor API change.
  page as (
    select * from joined order by created_at desc limit v_limit
  )
  select jsonb_build_object(
    'rows',        coalesce(jsonb_agg(j order by j.created_at desc), '[]'::jsonb),
    'next_cursor', case
                     when (select count(*) from joined) > v_limit
                     then (select min(created_at) from page)
                     else null
                   end
  )
    into v_rows
    from page j;

  return v_rows;
end;
$$;
revoke all on function public.feed_reels(timestamptz, int, text, text, text, text, text) from public;
grant execute on function public.feed_reels(timestamptz, int, text, text, text, text, text) to authenticated;


-- ============================================================
-- 8. get_reel(p_id) — single-reel fetch (deep link / share view)
-- Same shape as one row from feed_reels.
-- ============================================================
create or replace function public.get_reel(p_id uuid)
returns jsonb
language plpgsql
stable
security definer
set search_path = public
as $$
declare
  v_uid uuid := auth.uid();
  v_payload jsonb;
begin
  with r as (
    select * from public.reels
     where id = p_id
       and public.can_read_reel(visibility, author_id)
  )
  select jsonb_build_object(
    'id',           r.id,
    'symbol',       r.symbol,
    'market',       r.market,
    'chart_snapshot_url', r.chart_snapshot_url,
    'thesis',       r.thesis,
    'entry',        r.entry,
    'stop_loss',    r.stop_loss,
    'target',       r.target,
    'direction',    r.direction,
    'visibility',   r.visibility,
    'created_at',   r.created_at,
    'paper_trade_id', r.paper_trade_id,
    'paper_trade_qty',   pt.qty,
    'paper_trade_side',  pt.side,
    'paper_trade_entry', pt.entry_price,
    'author', jsonb_build_object(
      'id',           p.id,
      'username',     p.username,
      'display_name', p.display_name,
      'tier',         p.tier,
      'avatar_color', p.avatar_color,
      'win_rate', (
        select round(100.0 * count(*) filter (
                 where status = 'closed'
                   and ((side='buy'  and exit_price > entry_price)
                     or (side='sell' and exit_price < entry_price))
               )::numeric / nullif(count(*) filter (where status = 'closed'), 0), 1)
          from public.paper_trades where owner_id = p.id),
      'closed_n', (
        select count(*) filter (where status = 'closed')
          from public.paper_trades where owner_id = p.id)
    ),
    'tags', coalesce((
      select jsonb_agg(jsonb_build_object(
        'tag_type',  t.tag_type,
        'tag_value', t.tag_value,
        'x_pct',     t.x_pct,
        'y_pct',     t.y_pct,
        'ordinal',   t.ordinal
      ) order by t.ordinal, t.id)
        from public.reel_tags t
       where t.reel_id = r.id
    ), '[]'::jsonb),
    'counts', jsonb_build_object(
      'likes',   (select count(*) from public.reel_engagement where reel_id = r.id and kind = 'like'),
      'saves',   (select count(*) from public.reel_engagement where reel_id = r.id and kind = 'save'),
      'shares',  (select count(*) from public.reel_engagement where reel_id = r.id and kind = 'share'),
      'views',   (select count(*) from public.reel_engagement where reel_id = r.id and kind = 'view'),
      'mirrors', (select count(*) from public.reel_mirrors    where reel_id = r.id)
    ),
    'viewer_state', jsonb_build_object(
      'liked',     exists (select 1 from public.reel_engagement where reel_id = r.id and user_id = v_uid and kind = 'like'),
      'saved',     exists (select 1 from public.reel_engagement where reel_id = r.id and user_id = v_uid and kind = 'save'),
      'mirrored',  exists (select 1 from public.reel_mirrors    where reel_id = r.id and mirrored_by = v_uid),
      'following', exists (select 1 from public.follows         where follower_id = v_uid and followee_id = p.id)
    )
  )
    into v_payload
    from r
    join public.profiles p on p.id = r.author_id
    left join public.paper_trades pt on pt.id = r.paper_trade_id;

  return v_payload;
end;
$$;
revoke all on function public.get_reel(uuid) from public;
grant execute on function public.get_reel(uuid) to authenticated;

-- ===== 0004_schools.sql =======================================================
-- ============================================================================
-- TradeArena · Task #6: Schools (curated, ordered playlists of reels with
-- quizzes, paper-trade challenges, and perks).
--
-- Run after 0003_reels_engine.sql.
--
-- Conventions kept consistent with prior migrations:
--   * Every cross-user write goes through a SECURITY DEFINER RPC. The
--     base tables have minimal RLS; clients never write directly.
--   * Every new RPC `revoke all from public` then `grant execute to
--     authenticated` so anonymous callers can't invoke them even if
--     PUBLIC retains the default privilege somewhere upstream.
--   * Admin-only RPCs check `is_admin` themselves (no separate role).
-- ============================================================================

-- ----------------------------------------------------------------------------
-- 1. Tables
-- ----------------------------------------------------------------------------
create table if not exists public.schools (
  id            uuid primary key default gen_random_uuid(),
  slug          text unique not null,
  title         text not null,
  summary       text not null default '',
  icon          text not null default 'fa-graduation-cap',  -- font-awesome
  accent_color  text not null default '#c9a030',
  ordinal       int  not null default 0,
  created_at    timestamptz not null default now()
);

create table if not exists public.school_modules (
  id          uuid primary key default gen_random_uuid(),
  school_id   uuid not null references public.schools(id) on delete cascade,
  ordinal     int  not null,
  title       text not null,
  summary     text not null default '',
  created_at  timestamptz not null default now(),
  unique (school_id, ordinal)
);
create index if not exists school_modules_school_idx
  on public.school_modules(school_id, ordinal);

create table if not exists public.module_reels (
  module_id   uuid not null references public.school_modules(id) on delete cascade,
  reel_id     uuid not null references public.reels(id)         on delete cascade,
  ordinal     int  not null,
  primary key (module_id, ordinal)
);
create index if not exists module_reels_reel_idx on public.module_reels(reel_id);

-- One quiz per module (questions jsonb is an ordered array of
-- {q, choices:[...], correct:int, explain?}). Stored inline rather than
-- normalised because quizzes are short, never queried by question, and
-- always read as a single blob.
create table if not exists public.quizzes (
  module_id   uuid primary key references public.school_modules(id) on delete cascade,
  questions   jsonb not null default '[]'::jsonb,
  pass_pct    int   not null default 70 check (pass_pct between 0 and 100),
  updated_at  timestamptz not null default now()
);

create table if not exists public.quiz_attempts (
  id           uuid primary key default gen_random_uuid(),
  module_id    uuid not null references public.school_modules(id) on delete cascade,
  user_id      uuid not null references public.profiles(id)       on delete cascade,
  score        int  not null,
  total        int  not null,
  passed       boolean not null,
  answers      jsonb not null default '[]'::jsonb,  -- [{q, picked, correct}]
  attempted_at timestamptz not null default now()
);
create index if not exists quiz_attempts_user_idx
  on public.quiz_attempts(user_id, module_id, attempted_at desc);

-- One challenge per module. spec.kind drives the validator. Supported:
--   {kind:'min_trades',       params:{n:5, market?:'asx'}}
--   {kind:'consecutive_wins', params:{n:3, tag?:'breakout'}}
--   {kind:'min_rr',           params:{n:1, ratio:2.0, min_hold_days?:3, market?:'asx'}}
--   {kind:'journal_count',    params:{n:5, days:7}}
create table if not exists public.challenges (
  module_id   uuid primary key references public.school_modules(id) on delete cascade,
  title       text not null,
  summary     text not null default '',
  spec        jsonb not null,
  updated_at  timestamptz not null default now()
);

create table if not exists public.challenge_completions (
  id            uuid primary key default gen_random_uuid(),
  module_id     uuid not null references public.school_modules(id) on delete cascade,
  user_id       uuid not null references public.profiles(id)       on delete cascade,
  evidence      jsonb not null default '{}'::jsonb,  -- e.g. {trade_ids:[...], note:'...'}
  completed_at  timestamptz not null default now(),
  unique (module_id, user_id)
);

-- Perks granted on module completion. Same row-shape regardless of kind:
--   kind='extra_capital'     value:{amount: 5000}
--   kind='indicator_unlock'  value:{indicator: 'macd'}
--   kind='badge'             value:{key, label, icon}
create table if not exists public.user_perks (
  id            uuid primary key default gen_random_uuid(),
  user_id       uuid not null references public.profiles(id)       on delete cascade,
  kind          text not null check (kind in ('extra_capital','indicator_unlock','badge')),
  value         jsonb not null default '{}'::jsonb,
  source_module_id uuid references public.school_modules(id) on delete set null,
  granted_at    timestamptz not null default now(),
  unique (user_id, kind, source_module_id)
);
create index if not exists user_perks_user_idx on public.user_perks(user_id);

-- ----------------------------------------------------------------------------
-- 2. RLS
-- ----------------------------------------------------------------------------
-- Catalogue tables are public-read for any signed-in user. Writes only
-- through admin RPCs (which are SECURITY DEFINER and check is_admin).
alter table public.schools                enable row level security;
alter table public.school_modules         enable row level security;
alter table public.module_reels           enable row level security;
alter table public.quizzes                enable row level security;
alter table public.challenges             enable row level security;
alter table public.quiz_attempts          enable row level security;
alter table public.challenge_completions  enable row level security;
alter table public.user_perks             enable row level security;

drop policy if exists schools_read           on public.schools;
drop policy if exists school_modules_read    on public.school_modules;
drop policy if exists module_reels_read      on public.module_reels;
drop policy if exists quizzes_read           on public.quizzes;
drop policy if exists challenges_read        on public.challenges;
drop policy if exists quiz_attempts_read     on public.quiz_attempts;
drop policy if exists challenge_compls_read  on public.challenge_completions;
drop policy if exists user_perks_read        on public.user_perks;

create policy schools_read          on public.schools          for select using (auth.role() = 'authenticated');
create policy school_modules_read   on public.school_modules   for select using (auth.role() = 'authenticated');
create policy module_reels_read     on public.module_reels     for select using (auth.role() = 'authenticated');
-- NB: NO direct select policy on `quizzes`. The `correct` answer
-- indices are sensitive — exposing them through table RLS would let
-- an authenticated user trivially cheat, even though `get_module`
-- strips them on the way out. All quiz reads must go through:
--   * public.get_module     — strips correct + explain (player path)
--   * public.admin_get_quiz — admin-only round-trip (curator path)
-- Both are SECURITY DEFINER and therefore bypass RLS legitimately.
create policy challenges_read       on public.challenges       for select using (auth.role() = 'authenticated');

-- Personal tables: owner-only. All writes happen through SECURITY DEFINER RPCs.
create policy quiz_attempts_read    on public.quiz_attempts          for select using (user_id = auth.uid());
create policy challenge_compls_read on public.challenge_completions  for select using (user_id = auth.uid());
create policy user_perks_read       on public.user_perks             for select using (user_id = auth.uid());

-- ----------------------------------------------------------------------------
-- 3. Reader RPCs
-- ----------------------------------------------------------------------------

-- list_schools — index page. Returns each school + module count + the
-- viewer's progress (modules completed = both quiz passed AND challenge
-- passed). Signed-in only.
create or replace function public.list_schools()
returns jsonb
language plpgsql
security definer
set search_path = public, pg_temp
as $$
declare
  v_uid uuid := auth.uid();
  v_out jsonb;
begin
  if v_uid is null then raise exception 'not authenticated'; end if;

  with mod_counts as (
    select s.id as school_id, count(m.id) as module_count
      from public.schools s
      left join public.school_modules m on m.school_id = s.id
     group by s.id
  ),
  done as (
    -- count DISTINCT module ids — without this, a learner with two
    -- passing quiz attempts on the same module would have done_count
    -- bumped twice (joining qa once per row), which broke the progress
    -- ring (could exceed 100%).
    select m.school_id, count(distinct m.id) as done_count
      from public.school_modules m
      join public.quiz_attempts qa
        on qa.module_id = m.id and qa.user_id = v_uid and qa.passed
      join public.challenge_completions cc
        on cc.module_id = m.id and cc.user_id = v_uid
     group by m.school_id
  )
  select jsonb_agg(jsonb_build_object(
    'id',           s.id,
    'slug',         s.slug,
    'title',        s.title,
    'summary',      s.summary,
    'icon',         s.icon,
    'accent_color', s.accent_color,
    'module_count', coalesce(mc.module_count, 0),
    'done_count',   coalesce(d.done_count, 0)
  ) order by s.ordinal, s.title)
    into v_out
    from public.schools s
    left join mod_counts mc on mc.school_id = s.id
    left join done       d  on d.school_id  = s.id;

  return coalesce(v_out, '[]'::jsonb);
end $$;

-- get_school — detail page. School + ordered module list with each
-- module's lock status (a module is unlocked when the previous module
-- by ordinal is fully complete; the first module is always unlocked).
create or replace function public.get_school(p_id uuid)
returns jsonb
language plpgsql
security definer
set search_path = public, pg_temp
as $$
declare
  v_uid uuid := auth.uid();
  v_school jsonb;
  v_modules jsonb;
begin
  if v_uid is null then raise exception 'not authenticated'; end if;

  select jsonb_build_object(
    'id',           s.id,  'slug', s.slug, 'title', s.title,
    'summary',      s.summary,
    'icon',         s.icon, 'accent_color', s.accent_color
  ) into v_school
    from public.schools s
   where s.id = p_id;

  if v_school is null then raise exception 'school not found'; end if;

  -- Per-module status for this user.
  with status as (
    select m.id as module_id,
           exists(select 1 from public.quiz_attempts qa
                   where qa.module_id = m.id and qa.user_id = v_uid and qa.passed) as quiz_passed,
           exists(select 1 from public.challenge_completions cc
                   where cc.module_id = m.id and cc.user_id = v_uid) as challenge_passed,
           (select count(*) from public.module_reels mr where mr.module_id = m.id) as reel_count,
           exists(select 1 from public.quizzes q where q.module_id = m.id) as has_quiz,
           exists(select 1 from public.challenges c where c.module_id = m.id) as has_challenge
      from public.school_modules m
     where m.school_id = p_id
  ),
  ordered as (
    select m.*, st.quiz_passed, st.challenge_passed, st.reel_count, st.has_quiz, st.has_challenge,
           (st.quiz_passed and st.challenge_passed) as is_complete,
           -- Previous module is the one with the largest ordinal less than ours.
           lag( (st.quiz_passed and st.challenge_passed) ) over (order by m.ordinal) as prev_complete,
           row_number() over (order by m.ordinal) as rn
      from public.school_modules m
      join status st on st.module_id = m.id
     where m.school_id = p_id
  )
  select jsonb_agg(jsonb_build_object(
    'id',                o.id,
    'ordinal',           o.ordinal,
    'title',             o.title,
    'summary',           o.summary,
    'reel_count',        o.reel_count,
    'has_quiz',          o.has_quiz,
    'has_challenge',     o.has_challenge,
    'quiz_passed',       o.quiz_passed,
    'challenge_passed',  o.challenge_passed,
    'is_complete',       o.is_complete,
    -- First module (rn=1) always unlocked; others unlocked when the
    -- previous module is fully complete.
    'is_unlocked',       (o.rn = 1) or coalesce(o.prev_complete, false)
  ) order by o.ordinal)
    into v_modules
    from ordered o;

  return jsonb_build_object('school', v_school, 'modules', coalesce(v_modules, '[]'::jsonb));
end $$;

-- get_module — full module payload for the player page: ordered reels
-- (same shape as feed_reels rows so reels.html-style cards can render
-- unchanged), the quiz (sans correct-answer indices — those stay
-- server-side until submit_quiz), the challenge spec, and the user's
-- last attempt summary + completion status.
create or replace function public.get_module(p_id uuid)
returns jsonb
language plpgsql
security definer
set search_path = public, pg_temp
as $$
declare
  v_uid uuid := auth.uid();
  v_module jsonb;
  v_reels  jsonb;
  v_quiz   jsonb;
  v_challenge jsonb;
  v_attempt jsonb;
  v_completed boolean;
  v_school_id uuid;
begin
  if v_uid is null then raise exception 'not authenticated'; end if;

  select jsonb_build_object(
    'id', m.id, 'school_id', m.school_id, 'ordinal', m.ordinal,
    'title', m.title, 'summary', m.summary,
    'school_title', s.title, 'school_slug', s.slug, 'accent_color', s.accent_color
  ), m.school_id
    into v_module, v_school_id
    from public.school_modules m
    join public.schools s on s.id = m.school_id
   where m.id = p_id;
  if v_module is null then raise exception 'module not found'; end if;

  -- Ordered reels with author + tag list. Trimmed shape; the player
  -- page renders simpler cards than the full feed.
  with mr as (
    select reel_id, ordinal from public.module_reels where module_id = p_id
  ),
  tag_lists as (
    select t.reel_id, jsonb_agg(jsonb_build_object(
      'tag_type', t.tag_type, 'tag_value', t.tag_value,
      'x_pct', t.x_pct, 'y_pct', t.y_pct, 'ordinal', t.ordinal
    ) order by t.ordinal) as tags
      from public.reel_tags t
     where t.reel_id in (select reel_id from mr)
     group by t.reel_id
  )
  select jsonb_agg(jsonb_build_object(
    'ordinal', mr.ordinal,
    'reel', jsonb_build_object(
      'id',           r.id,    'symbol', r.symbol,    'market', r.market,
      'chart_snapshot_url', r.chart_snapshot_url,
      'thesis',       r.thesis,'entry',  r.entry,     'stop_loss', r.stop_loss,
      'target',       r.target,'direction', r.direction,
      'created_at',   r.created_at,
      'author', jsonb_build_object(
        'username',     p.username,
        'display_name', p.display_name,
        'tier',         p.tier,
        'avatar_color', p.avatar_color
      ),
      'tags', coalesce(tl.tags, '[]'::jsonb)
    )
  ) order by mr.ordinal)
    into v_reels
    from mr
    join public.reels r       on r.id = mr.reel_id
    join public.public_profiles p on p.id = r.author_id
    left join tag_lists tl    on tl.reel_id = r.id;

  -- Quiz: strip correct-answer indices before sending to client.
  select jsonb_build_object(
    'pass_pct', q.pass_pct,
    'questions', (
      select jsonb_agg(jsonb_build_object(
        'q',       elem->>'q',
        'choices', elem->'choices',
        -- explain is intentionally omitted until after submission
        'idx',     idx - 1
      ))
        from jsonb_array_elements(q.questions) with ordinality as t(elem, idx)
    )
  ) into v_quiz
    from public.quizzes q
   where q.module_id = p_id;

  select jsonb_build_object(
    'title', c.title, 'summary', c.summary, 'spec', c.spec
  ) into v_challenge
    from public.challenges c
   where c.module_id = p_id;

  -- Best (most recent passing) attempt summary, or just most recent.
  select jsonb_build_object(
    'score', qa.score, 'total', qa.total, 'passed', qa.passed,
    'attempted_at', qa.attempted_at
  ) into v_attempt
    from public.quiz_attempts qa
   where qa.module_id = p_id and qa.user_id = v_uid
   order by qa.passed desc, qa.attempted_at desc
   limit 1;

  v_completed := exists(
    select 1 from public.challenge_completions cc
     where cc.module_id = p_id and cc.user_id = v_uid
  );

  return jsonb_build_object(
    'module',    v_module,
    'reels',     coalesce(v_reels,  '[]'::jsonb),
    'quiz',      v_quiz,
    'challenge', v_challenge,
    'attempt',   v_attempt,
    'challenge_passed', v_completed
  );
end $$;

-- ----------------------------------------------------------------------------
-- 4. Submission RPCs (quiz + challenge)
-- ----------------------------------------------------------------------------

-- submit_quiz — server scores answers against the canonical questions
-- jsonb. Returns the per-question correctness map so the UI can show
-- instant feedback without a follow-up read. Inserts an attempt row
-- regardless of pass/fail (drives Profile streak math).
create or replace function public.submit_quiz(
  p_module_id uuid,
  p_answers   jsonb           -- [int, int, ...] picked-choice index per question
) returns jsonb
language plpgsql
security definer
set search_path = public, pg_temp
as $$
declare
  v_uid uuid := auth.uid();
  v_questions jsonb;
  v_pass_pct  int;
  v_total int := 0;
  v_score int := 0;
  v_passed boolean;
  v_per jsonb := '[]'::jsonb;
  v_idx int;
  v_q jsonb;
  v_picked int;
  v_correct int;
begin
  if v_uid is null then raise exception 'not authenticated'; end if;

  select questions, pass_pct into v_questions, v_pass_pct
    from public.quizzes where module_id = p_module_id;
  if v_questions is null then raise exception 'no quiz for module'; end if;
  if jsonb_typeof(p_answers) <> 'array' then raise exception 'answers must be a jsonb array'; end if;

  v_total := jsonb_array_length(v_questions);

  for v_idx in 0 .. v_total - 1 loop
    v_q := v_questions -> v_idx;
    v_correct := (v_q ->> 'correct')::int;
    -- coerce picked safely; out-of-range / missing = wrong
    begin
      v_picked := (p_answers ->> v_idx)::int;
    exception when others then v_picked := -1; end;
    if v_picked = v_correct then v_score := v_score + 1; end if;
    v_per := v_per || jsonb_build_array(jsonb_build_object(
      'idx', v_idx,
      'picked', v_picked,
      'correct', v_correct,
      'right', v_picked = v_correct,
      'explain', v_q -> 'explain'
    ));
  end loop;

  v_passed := v_total > 0 and (v_score * 100 / v_total) >= v_pass_pct;

  insert into public.quiz_attempts(module_id, user_id, score, total, passed, answers)
    values (p_module_id, v_uid, v_score, v_total, v_passed, p_answers);

  return jsonb_build_object(
    'score', v_score, 'total', v_total, 'passed', v_passed,
    'pass_pct', v_pass_pct, 'per_question', v_per
  );
end $$;

-- validate_challenge — runs the challenge.spec against the user's
-- paper_trades / quiz_attempts. The skill spec called for a Supabase
-- Edge Function for this; we kept it inline as a SECURITY DEFINER RPC
-- because (a) the existing reels engine already uses RPCs not Edge
-- Functions, (b) all the data lives in Postgres so an HTTP hop adds
-- latency without isolation benefit, and (c) gating + perk grant must
-- be transactional with the completion insert.
--
-- Supported spec.kind:
--   * min_trades       — N closed trades, optional market filter.
--   * consecutive_wins — last N closed trades all winners; optional
--                        tag filter (matches reel_tags on the source
--                        reel of the trade).
--   * min_rr           — N trades with realised R:R >= ratio; optional
--                        min_hold_days, market filter.
--   * journal_count    — N paper_trades opened in last `days` whose
--                        notes are non-empty.
-- Returns {passed, evidence, perk?}. On a fresh pass, also inserts
-- challenge_completions and grants the configured perk (if any). The
-- perk lives on the challenge.spec under `perk: {kind, value, badge?}`.
create or replace function public.validate_challenge(p_module_id uuid)
returns jsonb
language plpgsql
security definer
set search_path = public, pg_temp
as $$
declare
  v_uid uuid := auth.uid();
  v_spec jsonb;
  v_kind text;
  v_params jsonb;
  v_passed boolean := false;
  v_evidence jsonb := '{}'::jsonb;
  v_already boolean;
  v_perk jsonb;
  v_n int;
  v_market text;
  v_tag text;
  v_ratio numeric;
  v_min_hold int;
  v_days int;
  v_count int;
  v_trade_ids uuid[];
  v_streak int := 0;
  v_t record;
  v_has_quiz boolean;
  v_quiz_passed boolean;
begin
  if v_uid is null then raise exception 'not authenticated'; end if;

  select spec into v_spec from public.challenges where module_id = p_module_id;
  if v_spec is null then raise exception 'no challenge for module'; end if;

  -- Module-completion gate: a learner must pass the quiz BEFORE the
  -- challenge can grant a completion / perk. This RPC is callable
  -- directly by any authenticated user — without this gate they could
  -- skip straight from the reels stage to validate_challenge.
  -- (Modules without a quiz are allowed to bypass this check.)
  select exists(select 1 from public.quizzes q where q.module_id = p_module_id)
    into v_has_quiz;
  if v_has_quiz then
    select exists(select 1 from public.quiz_attempts qa
                   where qa.module_id = p_module_id
                     and qa.user_id  = v_uid
                     and qa.passed)
      into v_quiz_passed;
    if not v_quiz_passed then
      return jsonb_build_object(
        'passed',  false,
        'evidence', '{}'::jsonb,
        'perk',     null,
        'already_completed', false,
        'gate',     'quiz_required',
        'message',  'Pass the quiz first to unlock the challenge.'
      );
    end if;
  end if;

  v_kind   := v_spec ->> 'kind';
  v_params := coalesce(v_spec -> 'params', '{}'::jsonb);
  v_perk   := v_spec -> 'perk';

  if v_kind = 'min_trades' then
    v_n := coalesce((v_params ->> 'n')::int, 1);
    v_market := v_params ->> 'market';
    select array_agg(id), count(*) into v_trade_ids, v_count
      from (select id from public.paper_trades
             where owner_id = v_uid and status = 'closed'
               and (v_market is null or market = v_market)
             order by closed_at desc limit v_n) t;
    v_passed := coalesce(v_count, 0) >= v_n;
    v_evidence := jsonb_build_object('trade_ids', to_jsonb(coalesce(v_trade_ids, '{}')),
                                     'have', coalesce(v_count, 0), 'need', v_n);

  elsif v_kind = 'consecutive_wins' then
    v_n   := coalesce((v_params ->> 'n')::int, 3);
    v_tag := lower(coalesce(v_params ->> 'tag', ''));
    v_trade_ids := '{}';
    for v_t in
      select pt.id, pt.side, pt.entry_price, pt.exit_price, pt.source_reel_id
        from public.paper_trades pt
       where pt.owner_id = v_uid and pt.status = 'closed'
         and (v_tag = '' or exists (
              select 1 from public.reel_tags rt
               where rt.reel_id = pt.source_reel_id
                 and lower(rt.tag_value) = v_tag))
       order by pt.closed_at desc
       limit v_n
    loop
      if (v_t.side = 'buy'  and v_t.exit_price > v_t.entry_price) or
         (v_t.side = 'sell' and v_t.exit_price < v_t.entry_price) then
        v_streak   := v_streak + 1;
        v_trade_ids := v_trade_ids || v_t.id;
      else
        exit;
      end if;
    end loop;
    v_passed := v_streak >= v_n;
    v_evidence := jsonb_build_object('streak', v_streak, 'need', v_n,
                                     'trade_ids', to_jsonb(v_trade_ids),
                                     'tag', nullif(v_tag, ''));

  elsif v_kind = 'min_rr' then
    v_n        := coalesce((v_params ->> 'n')::int, 1);
    v_ratio    := coalesce((v_params ->> 'ratio')::numeric, 2);
    v_min_hold := coalesce((v_params ->> 'min_hold_days')::int, 0);
    v_market   := v_params ->> 'market';
    select array_agg(id), count(*) into v_trade_ids, v_count
      from (
        select pt.id
          from public.paper_trades pt
         where pt.owner_id = v_uid and pt.status = 'closed'
           and pt.stop_loss is not null and pt.target is not null
           and (v_market is null or pt.market = v_market)
           and abs(pt.target - pt.entry_price) /
               nullif(abs(pt.entry_price - pt.stop_loss), 0) >= v_ratio
           and (v_min_hold = 0 or
                extract(epoch from (coalesce(pt.closed_at, now()) - pt.opened_at))
                  / 86400.0 >= v_min_hold)
      ) t;
    v_passed := coalesce(v_count, 0) >= v_n;
    v_evidence := jsonb_build_object('trade_ids', to_jsonb(coalesce(v_trade_ids, '{}')),
                                     'have', coalesce(v_count, 0),
                                     'need', v_n, 'ratio', v_ratio,
                                     'min_hold_days', v_min_hold);

  elsif v_kind = 'journal_count' then
    v_n    := coalesce((v_params ->> 'n')::int, 1);
    v_days := coalesce((v_params ->> 'days')::int, 7);
    select count(*) into v_count
      from public.paper_trades pt
     where pt.owner_id = v_uid
       and pt.notes is not null and length(trim(pt.notes)) > 0
       and pt.opened_at >= now() - make_interval(days => v_days);
    v_passed := v_count >= v_n;
    v_evidence := jsonb_build_object('have', v_count, 'need', v_n, 'days', v_days);

  else
    raise exception 'unknown challenge kind: %', v_kind;
  end if;

  -- Idempotent insert + perk grant on a fresh pass.
  if v_passed then
    select exists(select 1 from public.challenge_completions
                   where module_id = p_module_id and user_id = v_uid)
      into v_already;
    if not v_already then
      insert into public.challenge_completions(module_id, user_id, evidence)
        values (p_module_id, v_uid, v_evidence);
      if v_perk is not null and v_perk ? 'kind' then
        insert into public.user_perks(user_id, kind, value, source_module_id)
          values (v_uid, v_perk ->> 'kind', coalesce(v_perk -> 'value', '{}'::jsonb), p_module_id)
          on conflict (user_id, kind, source_module_id) do nothing;
      end if;
    end if;
  end if;

  return jsonb_build_object(
    'passed',   v_passed,
    'evidence', v_evidence,
    'perk',     case when v_passed then v_perk else null end,
    'already_completed', coalesce(v_already, false)
  );
end $$;

-- ----------------------------------------------------------------------------
-- 5. Stats RPCs (Profile tile + perks list)
-- ----------------------------------------------------------------------------
create or replace function public.list_my_perks()
returns jsonb
language sql
security definer
set search_path = public, pg_temp
as $$
  select coalesce(jsonb_agg(jsonb_build_object(
    'id',         up.id,
    'kind',       up.kind,
    'value',      up.value,
    'granted_at', up.granted_at,
    'module_title', m.title,
    'school_title', s.title
  ) order by up.granted_at desc), '[]'::jsonb)
    from public.user_perks up
    left join public.school_modules m on m.id = up.source_module_id
    left join public.schools        s on s.id = m.school_id
   where up.user_id = auth.uid();
$$;

-- learning_stats(p_owner) — public-safe summary used by the Profile
-- "Learning" tile. Schools_completed = schools where every module has
-- both a passing quiz attempt AND a challenge completion. Streak =
-- consecutive days with at least one quiz attempt OR challenge
-- completion, ending at today.
create or replace function public.learning_stats(p_owner uuid)
returns jsonb
language plpgsql
security definer
set search_path = public, pg_temp
as $$
declare
  v_modules_completed int := 0;
  v_schools_completed int := 0;
  v_streak int := 0;
  v_today date := (now() at time zone 'utc')::date;
  v_d date;
  v_has boolean;
begin
  select count(*) into v_modules_completed
    from public.school_modules m
   where exists(select 1 from public.quiz_attempts qa
                 where qa.module_id = m.id and qa.user_id = p_owner and qa.passed)
     and exists(select 1 from public.challenge_completions cc
                 where cc.module_id = m.id and cc.user_id = p_owner);

  select count(*) into v_schools_completed
    from public.schools s
   where exists(select 1 from public.school_modules m where m.school_id = s.id)
     and not exists(
       select 1 from public.school_modules m
        where m.school_id = s.id
          and not (exists(select 1 from public.quiz_attempts qa
                           where qa.module_id = m.id and qa.user_id = p_owner and qa.passed)
                   and exists(select 1 from public.challenge_completions cc
                               where cc.module_id = m.id and cc.user_id = p_owner)));

  -- Walk back from today; first gap ends the streak.
  v_d := v_today;
  loop
    select exists(
      select 1 from public.quiz_attempts where user_id = p_owner
        and (attempted_at at time zone 'utc')::date = v_d
      union all
      select 1 from public.challenge_completions where user_id = p_owner
        and (completed_at at time zone 'utc')::date = v_d
    ) into v_has;
    exit when not v_has;
    v_streak := v_streak + 1;
    v_d := v_d - 1;
    -- safety belt — don't loop forever on misconfigured data
    exit when v_streak > 365;
  end loop;

  return jsonb_build_object(
    'schools_completed', v_schools_completed,
    'modules_completed', v_modules_completed,
    'streak',            v_streak
  );
end $$;

-- ----------------------------------------------------------------------------
-- 6. Admin curator RPCs
-- ----------------------------------------------------------------------------
create or replace function public.tarena_assert_admin()
returns void
language plpgsql
security definer
set search_path = public, pg_temp
as $$
begin
  if not exists(select 1 from public.profiles where id = auth.uid() and is_admin = true) then
    raise exception 'admin only';
  end if;
end $$;

create or replace function public.admin_upsert_school(p jsonb)
returns uuid
language plpgsql
security definer
set search_path = public, pg_temp
as $$
declare v_id uuid;
begin
  perform public.tarena_assert_admin();
  v_id := nullif(p ->> 'id', '')::uuid;
  if v_id is null then
    insert into public.schools(slug, title, summary, icon, accent_color, ordinal)
      values(p ->> 'slug', p ->> 'title', coalesce(p ->> 'summary',''),
             coalesce(p ->> 'icon','fa-graduation-cap'),
             coalesce(p ->> 'accent_color','#c9a030'),
             coalesce((p ->> 'ordinal')::int, 0))
      returning id into v_id;
  else
    update public.schools set
      slug = coalesce(p ->> 'slug', slug),
      title = coalesce(p ->> 'title', title),
      summary = coalesce(p ->> 'summary', summary),
      icon = coalesce(p ->> 'icon', icon),
      accent_color = coalesce(p ->> 'accent_color', accent_color),
      ordinal = coalesce((p ->> 'ordinal')::int, ordinal)
    where id = v_id;
  end if;
  return v_id;
end $$;

create or replace function public.admin_delete_school(p_id uuid)
returns void
language plpgsql
security definer
set search_path = public, pg_temp
as $$
begin
  perform public.tarena_assert_admin();
  delete from public.schools where id = p_id;
end $$;

create or replace function public.admin_upsert_module(p jsonb)
returns uuid
language plpgsql
security definer
set search_path = public, pg_temp
as $$
declare v_id uuid;
begin
  perform public.tarena_assert_admin();
  v_id := nullif(p ->> 'id', '')::uuid;
  if v_id is null then
    insert into public.school_modules(school_id, ordinal, title, summary)
      values((p ->> 'school_id')::uuid,
             coalesce((p ->> 'ordinal')::int, 1),
             p ->> 'title', coalesce(p ->> 'summary',''))
      returning id into v_id;
  else
    update public.school_modules set
      ordinal = coalesce((p ->> 'ordinal')::int, ordinal),
      title   = coalesce(p ->> 'title', title),
      summary = coalesce(p ->> 'summary', summary)
    where id = v_id;
  end if;
  return v_id;
end $$;

create or replace function public.admin_delete_module(p_id uuid)
returns void
language plpgsql
security definer
set search_path = public, pg_temp
as $$
begin
  perform public.tarena_assert_admin();
  delete from public.school_modules where id = p_id;
end $$;

create or replace function public.admin_set_module_reels(p_module_id uuid, p_reel_ids uuid[])
returns void
language plpgsql
security definer
set search_path = public, pg_temp
as $$
declare i int;
begin
  perform public.tarena_assert_admin();
  delete from public.module_reels where module_id = p_module_id;
  if p_reel_ids is null then return; end if;
  for i in 1 .. array_length(p_reel_ids, 1) loop
    insert into public.module_reels(module_id, reel_id, ordinal)
      values(p_module_id, p_reel_ids[i], i);
  end loop;
end $$;

create or replace function public.admin_upsert_quiz(p_module_id uuid, p_questions jsonb, p_pass_pct int)
returns void
language plpgsql
security definer
set search_path = public, pg_temp
as $$
begin
  perform public.tarena_assert_admin();
  insert into public.quizzes(module_id, questions, pass_pct, updated_at)
    values(p_module_id, p_questions, coalesce(p_pass_pct, 70), now())
    on conflict (module_id) do update set
      questions = excluded.questions,
      pass_pct  = excluded.pass_pct,
      updated_at = now();
end $$;

create or replace function public.admin_upsert_challenge(
  p_module_id uuid, p_title text, p_summary text, p_spec jsonb
) returns void
language plpgsql
security definer
set search_path = public, pg_temp
as $$
begin
  perform public.tarena_assert_admin();
  insert into public.challenges(module_id, title, summary, spec, updated_at)
    values(p_module_id, p_title, coalesce(p_summary,''), p_spec, now())
    on conflict (module_id) do update set
      title     = excluded.title,
      summary   = excluded.summary,
      spec      = excluded.spec,
      updated_at = now();
end $$;

-- admin_get_quiz — full quiz including correct-answer indices + explain
-- text, for the curator UI only. Public `get_module` strips these to
-- keep them server-side; this RPC re-exposes them gated on is_admin so
-- editing an existing quiz round-trips losslessly (otherwise saving
-- would silently reset every `correct` to 0).
create or replace function public.admin_get_quiz(p_module_id uuid)
returns jsonb
language plpgsql
security definer
set search_path = public, pg_temp
as $$
declare v_out jsonb;
begin
  perform public.tarena_assert_admin();
  select jsonb_build_object(
    'module_id', q.module_id,
    'pass_pct',  q.pass_pct,
    'questions', q.questions
  ) into v_out
    from public.quizzes q
   where q.module_id = p_module_id;
  return v_out;  -- null if no quiz
end $$;

-- admin_list_reels — autocomplete for the curator. Lightweight
-- projection — id, symbol, thesis (truncated), author handle.
create or replace function public.admin_list_reels(p_q text default '', p_limit int default 50)
returns jsonb
language plpgsql
security definer
set search_path = public, pg_temp
as $$
declare v_out jsonb;
begin
  perform public.tarena_assert_admin();
  -- Limit BEFORE aggregating — `limit` on the outer select with
  -- jsonb_agg() collapses to one row and would not actually cap the
  -- number of reels returned.
  with picked as (
    select r.id, r.symbol, r.thesis, r.created_at, p.username
      from public.reels r
      join public.public_profiles p on p.id = r.author_id
     where p_q = '' or r.symbol ilike '%'||p_q||'%' or r.thesis ilike '%'||p_q||'%' or p.username ilike '%'||p_q||'%'
     order by r.created_at desc
     limit greatest(1, least(coalesce(p_limit, 50), 200))
  )
  select coalesce(jsonb_agg(jsonb_build_object(
    'id', id, 'symbol', symbol,
    'thesis', left(thesis, 80),
    'author', username,
    'created_at', created_at
  ) order by created_at desc), '[]'::jsonb)
    into v_out
    from picked;
  return v_out;
end $$;

-- ----------------------------------------------------------------------------
-- 7. Seed two starter schools (idempotent)
-- ----------------------------------------------------------------------------
create or replace function public.seed_starter_schools()
returns void
language plpgsql
security definer
set search_path = public, pg_temp
as $$
declare
  v_school1 uuid; v_school2 uuid;
  v_m1 uuid; v_m2 uuid; v_m3 uuid; v_m4 uuid;
begin
  -- School 1: Reading Charts in 30 minutes (Technical 101)
  insert into public.schools(slug, title, summary, icon, accent_color, ordinal)
    values ('reading-charts-30',
            'Reading Charts in 30 Minutes',
            'A speed-run through the chart-reading skills every Aussie uni trader needs: candles, support/resistance, and the two indicators worth your screen real-estate.',
            'fa-chart-candlestick', '#c9a030', 1)
    on conflict (slug) do update set title = excluded.title returning id into v_school1;

  insert into public.school_modules(school_id, ordinal, title, summary)
    values (v_school1, 1, 'Candle Anatomy',
            'What every wick, body and shadow is telling you. Five-minute primer + the only quiz you need.')
    on conflict (school_id, ordinal) do update set title = excluded.title returning id into v_m1;

  insert into public.school_modules(school_id, ordinal, title, summary)
    values (v_school1, 2, 'Support & Resistance',
            'Drawing levels that actually matter — and trading the bounce vs the break.')
    on conflict (school_id, ordinal) do update set title = excluded.title returning id into v_m2;

  insert into public.school_modules(school_id, ordinal, title, summary)
    values (v_school1, 3, 'Two Indicators, No More',
            'Why most traders use 7 indicators and lose money. The case for EMA20 + RSI(14) and nothing else.')
    on conflict (school_id, ordinal) do update set title = excluded.title returning id into v_m3;

  perform public.admin_upsert_quiz_internal(v_m1, jsonb_build_array(
    jsonb_build_object('q', 'A long upper wick on a green candle most often signals…',
      'choices', jsonb_build_array('Strong continuation up','Sellers stepped in at the high','A bullish engulfing pattern','Insider buying'),
      'correct', 1, 'explain', 'The wick shows price was rejected from the high — sellers absorbed buying pressure.'),
    jsonb_build_object('q', 'A doji candle is best described as…',
      'choices', jsonb_build_array('A wide-bodied trend candle','Open ≈ close, signalling indecision','Always bearish','Always bullish'),
      'correct', 1, 'explain', 'Doji = open and close are roughly equal. It marks indecision; context (trend, location) decides direction.'),
    jsonb_build_object('q', 'On a 5-minute chart a single candle represents…',
      'choices', jsonb_build_array('5 trades','5 minutes of price action','5 ticks','5 percent move'),
      'correct', 1, 'explain', 'Candle interval = the chart timeframe. A 5m candle sums all trades in that 5-minute window.'),
    jsonb_build_object('q', 'A bullish engulfing requires…',
      'choices', jsonb_build_array('A green candle whose body fully engulfs the previous red body','A green candle with a long upper wick','Two green candles in a row','A doji followed by a green candle'),
      'correct', 0, 'explain', 'The green body must completely cover the prior red body — that''s what makes it a reversal pattern.')
  ), 75);

  perform public.admin_upsert_quiz_internal(v_m2, jsonb_build_array(
    jsonb_build_object('q', 'A horizontal level becomes "stronger" each time it…',
      'choices', jsonb_build_array('Is touched and respected','Is broken','Is ignored','Aligns with a Fib level'),
      'correct', 0, 'explain', 'Repeat touches that hold confirm market memory. Breaks weaken the level.'),
    jsonb_build_object('q', 'When support breaks decisively it usually…',
      'choices', jsonb_build_array('Disappears','Becomes new resistance','Becomes stronger support','Triggers a margin call'),
      'correct', 1, 'explain', 'Old support → new resistance ("polarity"). The price level retains psychological weight on the other side.'),
    jsonb_build_object('q', 'The best stop placement when buying a bounce off support is…',
      'choices', jsonb_build_array('At the support level','Just below the support level','At the previous high','No stop — average down'),
      'correct', 1, 'explain', 'A stop just below structure invalidates your trade idea cleanly when the level fails.')
  ), 70);

  perform public.admin_upsert_quiz_internal(v_m3, jsonb_build_array(
    jsonb_build_object('q', 'EMA20 reacts ___ than EMA50.',
      'choices', jsonb_build_array('Slower','Faster','The same','Only on weekly charts'),
      'correct', 1, 'explain', 'A shorter window weights recent price more heavily, so the EMA20 turns sooner.'),
    jsonb_build_object('q', 'RSI(14) above 70 is traditionally read as…',
      'choices', jsonb_build_array('Oversold','Overbought','Neutral','Bearish divergence'),
      'correct', 1, 'explain', 'But "overbought" doesn''t mean "sell" — strong trends stay above 70 for weeks.'),
    jsonb_build_object('q', 'The biggest risk of stacking 7 indicators is…',
      'choices', jsonb_build_array('Slower charts','Conflicting signals → analysis paralysis','Higher commissions','Broker rejection'),
      'correct', 1, 'explain', 'Indicators are derivatives of price. Adding more rarely adds information; it adds contradiction.')
  ), 70);

  perform public.admin_upsert_challenge_internal(v_m1, 'Spot 5 setups',
    'Open 5 paper trades on any market — practice committing to a thesis.',
    jsonb_build_object(
      'kind', 'min_trades',
      'params', jsonb_build_object('n', 5),
      'perk', jsonb_build_object('kind', 'extra_capital',
        'value', jsonb_build_object('amount', 5000))));

  perform public.admin_upsert_challenge_internal(v_m2, 'Trade a level',
    'Open one trade with a stop placed within 0.5% of a clear support/resistance level (R:R ≥ 2:1).',
    jsonb_build_object(
      'kind', 'min_rr',
      'params', jsonb_build_object('n', 1, 'ratio', 2),
      'perk', jsonb_build_object('kind', 'badge',
        'value', jsonb_build_object('key','level_trader','label','Level Trader','icon','fa-grip-lines'))));

  perform public.admin_upsert_challenge_internal(v_m3, 'Indicator discipline',
    'Document your reasoning on at least 3 trades this week — note which indicator triggered entry.',
    jsonb_build_object(
      'kind', 'journal_count',
      'params', jsonb_build_object('n', 3, 'days', 7),
      'perk', jsonb_build_object('kind','indicator_unlock',
        'value', jsonb_build_object('indicator','macd','label','MACD'))));

  -- School 2: Risk-First Trading (Risk Mgmt 101)
  insert into public.schools(slug, title, summary, icon, accent_color, ordinal)
    values ('risk-first',
            'Risk-First Trading',
            'Position sizing, stop placement, and the maths behind never blowing up your paper account. The course every retail trader skipped.',
            'fa-shield-halved', '#5b9cff', 2)
    on conflict (slug) do update set title = excluded.title returning id into v_school2;

  insert into public.school_modules(school_id, ordinal, title, summary)
    values (v_school2, 1, 'The 1% Rule',
            'Why risking 1% per trade survives a 10-trade losing streak — and 5% does not.')
    on conflict (school_id, ordinal) do update set title = excluded.title returning id into v_m4;

  perform public.admin_upsert_quiz_internal(v_m4, jsonb_build_array(
    jsonb_build_object('q', 'Risking 1% per trade, after 10 consecutive losses your account is at…',
      'choices', jsonb_build_array('~70% of starting','~90% of starting','~50% of starting','Wiped'),
      'correct', 1, 'explain', '0.99^10 ≈ 0.904. You still have ~90% — plenty of runway to recover.'),
    jsonb_build_object('q', 'Risking 10% per trade, after 10 consecutive losses your account is at…',
      'choices', jsonb_build_array('~90% of starting','~50% of starting','~35% of starting','Wiped'),
      'correct', 2, 'explain', '0.9^10 ≈ 0.349. You need a 186% return just to break even.'),
    jsonb_build_object('q', 'Position size = (account × risk%) ÷ ___',
      'choices', jsonb_build_array('Entry price','Distance from entry to stop','Distance from entry to target','Daily ATR'),
      'correct', 1, 'explain', 'The denominator is your per-share dollar risk = |entry − stop|. That converts dollar risk into share count.')
  ), 75);

  perform public.admin_upsert_challenge_internal(v_m4, 'Three winners in a row',
    'Demonstrate disciplined sizing with 3 consecutive winning closed trades.',
    jsonb_build_object(
      'kind', 'consecutive_wins',
      'params', jsonb_build_object('n', 3),
      'perk', jsonb_build_object('kind', 'badge',
        'value', jsonb_build_object('key','risk_first','label','Risk-First','icon','fa-shield-halved'))));
end $$;

-- Internal versions of the upsert RPCs that skip the admin check —
-- only called from within seed_starter_schools (also security definer).
create or replace function public.admin_upsert_quiz_internal(p_module_id uuid, p_questions jsonb, p_pass_pct int)
returns void language plpgsql security definer set search_path = public, pg_temp as $$
begin
  insert into public.quizzes(module_id, questions, pass_pct, updated_at)
    values(p_module_id, p_questions, coalesce(p_pass_pct, 70), now())
    on conflict (module_id) do update set
      questions = excluded.questions, pass_pct = excluded.pass_pct, updated_at = now();
end $$;

create or replace function public.admin_upsert_challenge_internal(
  p_module_id uuid, p_title text, p_summary text, p_spec jsonb
) returns void language plpgsql security definer set search_path = public, pg_temp as $$
begin
  insert into public.challenges(module_id, title, summary, spec, updated_at)
    values(p_module_id, p_title, coalesce(p_summary,''), p_spec, now())
    on conflict (module_id) do update set
      title = excluded.title, summary = excluded.summary,
      spec = excluded.spec, updated_at = now();
end $$;

